-- Schema for Domain: payroll | Business: Staffing Hr | Version: v1_mvm
-- Generated on: 2026-05-02 22:45:37

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `staffing_hr_ecm_v1`.`payroll` COMMENT 'Owns all worker pay and tax processing data. Covers gross pay calculation, pay rates, gross-to-net calculations, tax withholdings (FICA, FUTA, SUTA), burden rates, deductions, net pay, workers compensation insurance premiums, W-2 and 1099 tax form processing, payroll tax filing, PTO accruals, and benefits administration processed through TempWorks Payroll. Handles multi-state payroll compliance and supports EOR and co-employment payroll models.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`pay_run` (
    `pay_run_id` BIGINT COMMENT 'Unique system-generated identifier for each payroll processing cycle (pay run) executed through TempWorks Payroll. Serves as the primary key and authoritative anchor for all payroll transactions within a given cycle.',
    `pay_period_id` BIGINT COMMENT 'Foreign key linking to timesheet.pay_period. Business justification: pay_run has pay_period_start_date/end_date as plain columns but no FK to the authoritative pay_period record. Linking pay_run.pay_period_id → timesheet.pay_period is fundamental to payroll period reco',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the payroll run was formally approved by the authorized approver. Captured for audit trail, SLA compliance, and payroll processing timeline analytics.',
    `branch_code` STRING COMMENT 'Staffing branch or cost center code associated with this payroll run. Used for branch-level payroll cost allocation, P&L reporting, and operational analytics in Power BI.',
    `check_date` DATE COMMENT 'Date printed on physical payroll checks or used as the effective date for direct deposit transactions. May differ from pay_date when banking processing windows shift the settlement date.',
    `company_code` STRING COMMENT 'Identifier for the legal employing entity or EOR entity under which this payroll run is processed. Supports multi-entity payroll operations and co-employment models where Staffing Hr acts as the employer of record.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this pay run record was first created in TempWorks Payroll. Serves as the audit record creation timestamp for data lineage and SOC 2 Type II compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this payroll run. Typically USD for domestic operations; supports multi-currency for international EOR engagements.. Valid values are `^[A-Z]{3}$`',
    `disbursement_method` STRING COMMENT 'Primary method used to disburse net pay to workers in this run. Direct deposit (ACH) is standard; check and pay card are alternatives for workers without bank accounts; wire for special high-value payments.. Valid values are `direct_deposit|check|pay_card|wire`',
    `gl_post_date` DATE COMMENT 'Date on which this payroll runs journal entries were posted to the Oracle NetSuite ERP General Ledger. Marks the accounting period in which payroll costs are recognized.',
    `ic_worker_count` STRING COMMENT 'Number of 1099 independent contractors (ICs) included in this payroll run. Used for IRS 1099-NEC filing thresholds and worker classification compliance monitoring.',
    `is_multi_state` BOOLEAN COMMENT 'Indicates whether this payroll run spans workers in more than one US state, triggering multi-state tax withholding, SUTA apportionment, and additional compliance review requirements.',
    `pay_date` DATE COMMENT 'Scheduled date on which worker net pay is disbursed via direct deposit, check, or pay card. Determines the tax deposit due date per IRS deposit schedule rules.',
    `pay_frequency` STRING COMMENT 'Frequency at which workers are paid within this run. Drives pay period date calculations and tax withholding schedules per IRS Publication 15 annualization tables.. Valid values are `weekly|biweekly|semimonthly|monthly`',
    `payroll_state_codes` STRING COMMENT 'Comma-delimited list of two-letter US state codes (e.g., CA,TX,NY) representing all states in which workers were paid in this run. Drives multi-state tax filing obligations and SUTA rate application.',
    `posted_timestamp` TIMESTAMP COMMENT 'Date and time when this payroll run was finalized and posted to the General Ledger in Oracle NetSuite ERP, making it immutable for the accounting period.',
    `processed_timestamp` TIMESTAMP COMMENT 'Date and time when TempWorks Payroll completed the payroll calculation and tax computation processing for this run. Used for payroll operations SLA monitoring and processing time analytics.',
    `run_number` STRING COMMENT 'Externally-known alphanumeric identifier for the pay run, used in reconciliation, audit trails, and payroll operations communications. Format: PR-YYYY-MM-NNNN.. Valid values are `^PR-[0-9]{4}-[0-9]{2}-[0-9]{4}$`',
    `run_status` STRING COMMENT 'Current lifecycle state of the payroll run within TempWorks Payroll workflow. Progresses from open (data entry) through processing, approved, and posted (finalized to GL). Voided indicates the run was reversed.. Valid values are `open|processing|approved|posted|voided`',
    `run_type` STRING COMMENT 'Classification of the payroll run indicating its operational purpose. Regular runs cover standard pay periods; off-cycle handles out-of-band payments; adjustment corrects prior-period errors; void-and-reissue replaces a voided run; supplemental covers bonuses or special payments.. Valid values are `regular|off_cycle|adjustment|void_and_reissue|supplemental`',
    `tax_quarter` STRING COMMENT 'Calendar quarter (1–4) to which this payroll run belongs, used for IRS Form 941 quarterly payroll tax filing and FUTA/SUTA quarterly reporting.',
    `tax_year` STRING COMMENT 'Calendar year to which this payroll runs earnings and withholdings are attributed for IRS W-2 and 1099 tax reporting purposes. Critical for year-end tax form generation.',
    `total_deductions` DECIMAL(18,2) COMMENT 'Sum of all voluntary and involuntary employee deductions (benefits, garnishments, 401k, health insurance premiums, etc.) withheld from worker gross pay in this run. Reconciles gross-to-net pay calculations.',
    `total_dt_pay` DECIMAL(18,2) COMMENT 'Sum of double time (DT) earnings for all workers in this run, applicable in states such as California where DT is mandated for hours exceeding 12 in a workday or 8 on the seventh consecutive day.',
    `total_employer_burden` DECIMAL(18,2) COMMENT 'Sum of all employer-side payroll costs beyond gross wages in this run, including employer FICA, FUTA, SUTA, workers comp premiums, and employer-paid benefits. Used to calculate the burden rate and total cost of workforce deployment.',
    `total_fica_employee` DECIMAL(18,2) COMMENT 'Sum of employee-side Federal Insurance Contributions Act (FICA) withholdings (Social Security 6.2% + Medicare 1.45%) across all workers in this run. Reported on IRS Form 941.',
    `total_fica_employer` DECIMAL(18,2) COMMENT 'Sum of employer-side Federal Insurance Contributions Act (FICA) matching contributions (Social Security 6.2% + Medicare 1.45%) for all W-2 workers in this run. Included in total employer burden calculation.',
    `total_futa_tax` DECIMAL(18,2) COMMENT 'Sum of Federal Unemployment Tax Act (FUTA) employer tax accrued in this payroll run, calculated at 6.0% on the first $7,000 of each employees wages (net of SUTA credit). Filed annually on IRS Form 940.',
    `total_gross_pay` DECIMAL(18,2) COMMENT 'Sum of all gross earnings for all workers in this payroll run before any deductions or tax withholdings. Includes regular pay, overtime (OT), double time (DT), per diem, and other earnings components.',
    `total_net_pay` DECIMAL(18,2) COMMENT 'Sum of net pay disbursed to all workers in this run after all tax withholdings and deductions. Represents the total cash outflow for worker compensation and is the primary reconciliation figure against bank ACH/check totals.',
    `total_ot_pay` DECIMAL(18,2) COMMENT 'Sum of overtime (OT) premium earnings for all workers in this run, calculated at 1.5x the regular rate for hours exceeding 40 per workweek per FLSA. Supports OT cost monitoring and client billing reconciliation.',
    `total_per_diem_pay` DECIMAL(18,2) COMMENT 'Sum of per diem allowances paid to workers in this run for travel, lodging, and meal reimbursements. Per diem amounts within IRS GSA rates are non-taxable; amounts above are taxable wages.',
    `total_pto_pay` DECIMAL(18,2) COMMENT 'Sum of paid time off (PTO) earnings disbursed in this payroll run, including vacation, sick, and holiday pay. Supports PTO accrual reconciliation and state-mandated paid leave compliance.',
    `total_regular_pay` DECIMAL(18,2) COMMENT 'Sum of straight-time (regular rate) earnings for all workers in this run, excluding overtime, double time, and premium pay components. Used for pay rate analytics and FLSA regular rate of pay calculations.',
    `total_suta_tax` DECIMAL(18,2) COMMENT 'Sum of State Unemployment Tax Act (SUTA) employer tax accrued across all applicable states in this payroll run. Rates and wage bases vary by state; critical for multi-state payroll compliance.',
    `total_tax_withholding` DECIMAL(18,2) COMMENT 'Sum of all employee-side tax withholdings across all workers in this run, including federal income tax, state income tax, local taxes, and employee FICA (Social Security and Medicare). Used for IRS Form 941 and state tax deposit reconciliation.',
    `total_workers_comp_premium` DECIMAL(18,2) COMMENT 'Sum of workers compensation insurance premiums accrued for all workers in this payroll run, calculated based on payroll amounts and applicable workers comp class codes and rates. Supports insurance carrier reporting and burden rate analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this pay run record was last modified in TempWorks Payroll or the Silver Layer. Supports change data capture, data lineage, and audit trail requirements.',
    `void_reason` STRING COMMENT 'Business justification or reason code for voiding this payroll run. Required when run_status = voided to support audit compliance and payroll error tracking.',
    `voided_timestamp` TIMESTAMP COMMENT 'Date and time when this payroll run was voided, if applicable. Populated only for runs with run_status = voided. Supports payroll reversal audit trail and GL correction tracking.',
    `w2_worker_count` STRING COMMENT 'Number of W-2 (Wage and Tax Statement) employees included in this payroll run. Distinguishes co-employed temporary workers from independent contractors for tax and compliance reporting.',
    `worker_count` STRING COMMENT 'Total number of workers (W-2 employees and 1099 independent contractors) included in this payroll run. Used for headcount reporting, payroll audit reconciliation, and workforce analytics.',
    CONSTRAINT pk_pay_run PRIMARY KEY(`pay_run_id`)
) COMMENT 'Master record for each payroll processing cycle executed through TempWorks Payroll. Captures the payroll run header including pay period start and end dates, pay date, pay frequency, run type (regular, off-cycle, adjustment, void-and-reissue), run status (open, processing, approved, posted, voided), total gross pay, total net pay, total tax withholdings, total deductions, total employer burden, worker count, processing timestamps, and approver. Serves as the authoritative anchor for all payroll transactions within a given cycle and the primary reconciliation point for payroll operations.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`pay_stub` (
    `pay_stub_id` BIGINT COMMENT 'Unique system-generated identifier for each individual pay stub record. Primary key for the pay_stub data product. TRANSACTION_HEADER role — serves as the anchor for all gross-to-net pay disbursement details for a single worker in a single pay run.',
    `assignment_id` BIGINT COMMENT 'Reference to the placement assignment for which this pay stub was generated. Ties earnings to the specific client engagement, job order, and work location for labor cost allocation and billing reconciliation.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Pay stubs must reference governing MSA for audit trail, co-employment determination, and compliance verification. Required for client audits, dispute resolution, and demonstrating adherence to contrac',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: Payroll processing validates credential status before issuing payment; compliance holds block pay_stub generation when mandatory credentials expire. Staffing firms routinely hold paychecks until BGC/l',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Pay stubs must be validated against the credential package governing the assignment — staffing payroll audits run Pay Stubs by Credential Package to verify workers paid at premium rates hold the req',
    `direct_deposit_setup_id` BIGINT COMMENT 'Foreign key linking to timesheet.direct_deposit_setup. Business justification: pay_stub records ACH disbursement but has no FK to the direct_deposit_setup that governed it. Linking pay_stub.direct_deposit_setup_id → timesheet.direct_deposit_setup enables ACH return resolution an',
    `direct_hire_id` BIGINT COMMENT 'Foreign key linking to placement.direct_hire. Business justification: Direct hire employees receive pay stubs when staffing firm handles payroll during transition or under PEO arrangements. Links pay records to permanent placement for payroll continuity and compliance.',
    `everify_case_id` BIGINT COMMENT 'Foreign key linking to compliance.everify_case. Business justification: E-Verify case status must be resolved before continuing payroll for new hires at federal contractor clients. TNC (Tentative Non-Confirmation) cases require payroll suspension until resolution - federa',
    `i9_verification_id` BIGINT COMMENT 'Foreign key linking to compliance.i9_verification. Business justification: Every pay stub requires valid I-9 work authorization verification before payment issuance. Staffing firms cannot pay workers without documented work eligibility - core compliance gate for payroll proc',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC contractor payment processing requires referencing the IC agreement to validate payment_structure, payment_terms_net_days, and form_1099_reporting_flag when generating pay stubs. Staffing payroll t',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: Payroll validation requires verifying worker completed onboarding before issuing first paycheck. Links pay stub to the onboarding engagement that authorized payment. Critical for compliance audits and',
    `order_header_id` BIGINT COMMENT 'Foreign key linking to joborder.order_header. Business justification: Pay stubs must link to job orders for client billing reconciliation, revenue recognition by order, and job-level margin analysis. Essential for staffing P&L reporting and invoice validation against co',
    `pay_period_id` BIGINT COMMENT 'Foreign key linking to timesheet.pay_period. Business justification: pay_stub has pay_period_start_date/end_date as plain columns with no FK to the authoritative pay_period record. Linking pay_stub.pay_period_id → timesheet.pay_period normalizes period reference, enabl',
    `pay_rate_id` BIGINT COMMENT 'Foreign key linking to payroll.pay_rate. Business justification: A pay stub is generated based on a specific pay rate master record. Adding pay_rate_id to pay_stub creates a traceable link from the transactional pay statement back to the authoritative rate definiti',
    `pay_run_id` BIGINT COMMENT 'Reference to the payroll run batch that produced this pay stub. Enables grouping of all stubs processed in the same payroll cycle and supports reconciliation against the payroll run header.',
    `placement_compliance_check_id` BIGINT COMMENT 'Foreign key linking to compliance.placement_compliance_check. Business justification: Staffing payroll gates pay stub issuance on compliance clearance (I-9, BGC, drug screen). Payroll auditors reference the placement_compliance_check record to confirm a worker was legally authorized to',
    `profile_id` BIGINT COMMENT 'Reference to the worker (candidate/employee) for whom this pay stub was generated. Links to the candidate or worker master record in the staffing system. Supports PARTY_REFERENCE requirement for TRANSACTION_HEADER role.',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: W-2 workers on SOW engagements receive pay stubs. Links payroll record to SOW engagement for project cost tracking, client billing validation, and worker payment documentation.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: When workers are vendor-supplied (subcontractor model), pay stubs must track the originating vendor for cost allocation, vendor invoice validation, and dispute resolution. Accounts payable reconciliat',
    `timesheet_id` BIGINT COMMENT 'Foreign key linking to timesheet.timesheet. Business justification: Pay stubs are generated directly from approved timesheets in staffing operations. This link enables traceability from time worked to payment issued, critical for payroll audit, dispute resolution, and',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Pay stub generation requires validated wage/hour determinations to ensure compliant overtime calculations, salary basis tests, and prevailing wage compliance. Staffing payroll systems validate each pa',
    `wc_policy_id` BIGINT COMMENT 'Foreign key linking to payroll.wc_policy. Business justification: A pay stub captures workers_comp_premium (the actual WC premium charged on this pay cycle) and workers_comp_code (the NCCI class code). Adding wc_policy_id links the pay stub to the governing WC polic',
    `work_authorization_id` BIGINT COMMENT 'Foreign key linking to credentialing.work_authorization. Business justification: Work authorization validity at each pay date is a direct payroll compliance requirement — staffing firms must confirm active work authorization before disbursing pay. Payroll Compliance: Work Authori',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: Per diem eligibility and multi-state tax withholding on pay stubs depend on the specific work location. pay_stub carries work_state_code as a denormalized field; a direct FK to work_location enables p',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Pay stub processing depends on correct worker classification (W-2 vs 1099) to determine tax withholding obligations, FICA applicability, and reporting requirements. Classification drives payroll tax t',
    `account_type` STRING COMMENT 'Type of bank account designated for direct deposit disbursement. checking or savings as required by NACHA ACH transaction codes (PPD). Determines the ACH SEC code used in the payment file. Null for check and pay card disbursements.. Valid values are `checking|savings`',
    `ach_trace_number` STRING COMMENT 'Unique 15-digit NACHA ACH trace number assigned to the direct deposit transaction for this pay stub. Null for check and pay card disbursements. Used for ACH payment tracing, return item resolution, and bank reconciliation.',
    `check_number` STRING COMMENT 'Sequential check number printed on the physical paycheck when pay_delivery_method is check. Null for direct deposit and pay card disbursements. Used for check reconciliation, stop-payment requests, and positive pay bank file matching.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this pay stub record was first created in the payroll system. Satisfies RECORD_AUDIT_CREATED requirement for TRANSACTION_HEADER role. Used for audit trails and payroll processing SLA measurement.',
    `deposit_allocation_amount` DECIMAL(18,2) COMMENT 'Dollar amount or percentage value of net pay allocated to this account in a split-deposit arrangement. Populated when deposit_allocation_type is fixed_amount or percentage. Null when deposit_allocation_type is full_net.',
    `deposit_allocation_type` STRING COMMENT 'Specifies how net pay is allocated to this bank account in a split-deposit configuration. full_net = entire net pay to one account; fixed_amount = a specific dollar amount; percentage = a defined percentage of net pay. Supports multi-account direct deposit configurations.. Valid values are `full_net|fixed_amount|percentage`',
    `deposit_priority` STRING COMMENT 'Numeric sequence (1 = highest priority) determining the order in which net pay is allocated across multiple bank accounts in a split-deposit configuration. Ensures correct disbursement sequencing when a worker has designated multiple accounts.',
    `dt_earnings` DECIMAL(18,2) COMMENT 'Dollar amount of earnings for double-time hours (dt_hours × pay_rate × 2.0). Applicable in states with double-time mandates. Stored as a discrete earnings component for gross pay audit and state compliance reporting.',
    `dt_hours` DECIMAL(18,2) COMMENT 'Total double-time hours worked during the pay period, subject to the 2x pay multiplier. Applicable in states such as California with daily double-time thresholds (e.g., hours beyond 12 in a workday). Required for accurate gross pay calculation in multi-state payroll.',
    `federal_income_tax_withheld` DECIMAL(18,2) COMMENT 'Dollar amount of federal income tax withheld from the workers wages for this pay period based on W-4 elections and IRS withholding tables. Required for W-2 reporting (Box 2) and federal tax deposit obligations.',
    `futa_taxable_wages` DECIMAL(18,2) COMMENT 'Portion of the workers gross wages subject to Federal Unemployment Tax Act (FUTA) employer tax for this pay period, up to the $7,000 annual wage base. Required for IRS Form 940 filing and employer burden rate reporting.',
    `gross_pay` DECIMAL(18,2) COMMENT 'Total pre-deduction, pre-tax earnings for the pay period. Sum of regular_earnings, ot_earnings, dt_earnings, per_diem_amount, and any other pay components. Represents the gross-base amount in the MONETARY_TRIPLET for this transaction. Used as the basis for all tax withholding calculations.',
    `medicare_tax_withheld` DECIMAL(18,2) COMMENT 'Employee share of Medicare (HI) tax withheld under FICA at the applicable rate (1.45%, plus 0.9% Additional Medicare Tax for high earners). Required for W-2 reporting (Box 6) and FICA deposit compliance.',
    `net_pay` DECIMAL(18,2) COMMENT 'Final take-home amount disbursed to the worker after all deductions and tax withholdings (gross_pay − total_deductions − total_tax_withheld). Represents the net total in the MONETARY_TRIPLET. The amount actually paid via direct deposit, check, or pay card.',
    `ot_earnings` DECIMAL(18,2) COMMENT 'Dollar amount of earnings for overtime hours (ot_hours × pay_rate × 1.5). Stored separately from regular earnings to support FLSA compliance reporting, overtime cost analytics, and client billing reconciliation.',
    `ot_hours` DECIMAL(18,2) COMMENT 'Total overtime hours worked during the pay period, subject to the 1.5x pay multiplier under FLSA. Includes hours exceeding the standard weekly threshold or daily OT thresholds per applicable state law. Critical for gross pay calculation and FLSA compliance reporting.',
    `pay_date` DATE COMMENT 'The actual date on which payment was or is scheduled to be disbursed to the worker. Represents the principal business event date (BUSINESS_EVENT_TIMESTAMP category). Used for cash flow reporting, tax period assignment, and worker payment scheduling.',
    `pay_delivery_method` STRING COMMENT 'Method by which net pay is disbursed to the worker. direct_deposit = ACH electronic transfer to bank account; check = physical paper check; pay_card = prepaid debit card for unbanked workers. Determines downstream disbursement routing logic.. Valid values are `direct_deposit|check|pay_card`',
    `pay_frequency` STRING COMMENT 'Frequency at which the worker is paid, determining the pay period cadence for this stub. Drives payroll scheduling, tax withholding annualization, and benefit deduction timing. Most staffing workers are paid weekly or biweekly.. Valid values are `weekly|biweekly|semimonthly|monthly`',
    `pay_rate` DECIMAL(18,2) COMMENT 'The workers base hourly or unit pay rate applied during this pay period, expressed in USD. Represents the agreed compensation rate from the placement rate card. Used to calculate regular earnings and validate gross pay. Classified confidential as worker compensation data.',
    `pay_rate_type` STRING COMMENT 'Classification of the pay rate basis for this stub. hourly = standard time-based; salary = fixed periodic amount; per_diem = daily allowance-based; piece_rate = unit-of-output based. Determines gross pay calculation method and FLSA overtime applicability.. Valid values are `hourly|salary|per_diem|piece_rate`',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'Non-taxable per diem allowance paid to the worker for travel, meals, or lodging during the pay period. Sourced from approved per diem claims. Tracked separately from taxable wages for IRS accountable plan compliance and gross pay composition.',
    `prenote_status` STRING COMMENT 'Status of the NACHA prenote (zero-dollar test transaction) process for this bank account. pending = prenote initiated; sent = prenote transmitted to bank; verified = bank confirmed account valid; failed = account validation failed. Governs whether live ACH disbursement is permitted.. Valid values are `not_required|pending|sent|verified|failed`',
    `pto_accrual_balance` DECIMAL(18,2) COMMENT 'Workers remaining PTO accrual balance as of this pay stubs pay period end date, expressed in hours. Snapshot value captured at time of pay run for worker statement display and leave liability reporting.',
    `pto_hours_used` DECIMAL(18,2) COMMENT 'Number of PTO hours applied to this pay stub for the pay period. Represents paid leave hours that contribute to gross pay but are not worked hours. Required for PTO accrual balance management and FLSA leave tracking.',
    `regular_earnings` DECIMAL(18,2) COMMENT 'Dollar amount of earnings for regular straight-time hours (regular_hours × pay_rate). Core component of gross pay. Stored as a raw earnings component to support gross-to-net audit trail and payroll reconciliation.',
    `regular_hours` DECIMAL(18,2) COMMENT 'Total straight-time hours worked by the worker during the pay period, up to the overtime threshold (typically 40 hours per week under FLSA). Sourced from approved timesheet records in Kronos Workforce Ready. Used to calculate regular earnings.',
    `social_security_tax_withheld` DECIMAL(18,2) COMMENT 'Employee share of Social Security (OASDI) tax withheld under FICA at the applicable rate (6.2% up to the annual wage base). Required for W-2 reporting (Box 4) and FICA tax deposit compliance.',
    `state_income_tax_withheld` DECIMAL(18,2) COMMENT 'Dollar amount of state income tax withheld for the primary work state during this pay period. Supports multi-state payroll compliance and state W-2 / equivalent reporting. May be zero for states with no income tax.',
    `stub_number` STRING COMMENT 'Externally visible, human-readable identifier for this pay stub as printed on the workers pay statement (e.g., PS-2024-00045231). Used for worker inquiries, audit trails, and payroll reconciliation. Satisfies BUSINESS_IDENTIFIER requirement for TRANSACTION_HEADER role.',
    `stub_status` STRING COMMENT 'Current lifecycle state of the pay stub within the payroll processing workflow. draft = in calculation; calculated = gross-to-net complete pending approval; approved = authorized for disbursement; issued = payment released to worker; voided = cancelled before disbursement; reversed = post-issuance correction applied. Satisfies LIFECYCLE_STATUS requirement.. Valid values are `draft|calculated|approved|issued|voided|reversed`',
    `suta_taxable_wages` DECIMAL(18,2) COMMENT 'Portion of the workers gross wages subject to State Unemployment Tax Act (SUTA) employer tax for this pay period, up to the applicable state wage base. Required for state unemployment tax filing and workforce cost burden rate calculation.',
    `tax_filing_status` STRING COMMENT 'Workers federal income tax filing status as declared on IRS Form W-4, used to determine the correct withholding amount for this pay stub. [ENUM-REF-CANDIDATE: single|married_filing_jointly|married_filing_separately|head_of_household|exempt|qualifying_surviving_spouse — promote to reference product]. Valid values are `single|married_filing_jointly|married_filing_separately|head_of_household|exempt`',
    `total_deductions` DECIMAL(18,2) COMMENT 'Aggregate dollar amount of all pre-tax and post-tax deductions applied to this pay stub, including benefits premiums, garnishments, voluntary deductions, and advances. Represents the adjustment component of the MONETARY_TRIPLET. Supports gross-to-net reconciliation.',
    `total_tax_withheld` DECIMAL(18,2) COMMENT 'Aggregate dollar amount of all federal, state, and local taxes withheld from the workers gross pay for this pay period. Includes FICA (Social Security and Medicare), federal income tax, and applicable state/local income taxes. Key component of gross-to-net calculation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this pay stub record. Satisfies RECORD_AUDIT_UPDATED requirement for TRANSACTION_HEADER role. Tracks corrections, reversals, and status transitions for audit compliance.',
    `w2_eligible` BOOLEAN COMMENT 'Indicates whether this pay stub is associated with a W-2 employee (True) versus a 1099 independent contractor (False). Drives tax withholding applicability, FICA obligations, and year-end tax form generation routing in TempWorks Payroll.',
    `workers_comp_code` STRING COMMENT 'NCCI or state-specific workers compensation classification code assigned to the worker for this pay period based on job duties and work location. Drives workers comp premium calculation and is required for policy compliance and audit.',
    `workers_comp_premium` DECIMAL(18,2) COMMENT 'Employer-paid workers compensation insurance premium allocated to this pay stub for the pay period, calculated as (workers_comp_rate × payroll_basis). Represents a key component of the employer burden rate and total labor cost.',
    `ytd_gross_pay` DECIMAL(18,2) COMMENT 'Cumulative gross pay earned by the worker from the start of the calendar year through this pay stubs pay period end date. Displayed on the workers pay statement and used for W-2 wage box population, FICA wage base tracking, and annual compensation reporting.',
    `ytd_net_pay` DECIMAL(18,2) COMMENT 'Cumulative net pay disbursed to the worker from the start of the calendar year through this pay stubs pay period end date. Displayed on the workers pay statement for annual earnings visibility and financial planning.',
    `ytd_tax_withheld` DECIMAL(18,2) COMMENT 'Cumulative total of all taxes withheld from the workers pay from the start of the calendar year through this pay stubs pay period end date. Displayed on the pay statement and used for W-2 Box 2/4/6 population and tax deposit reconciliation.',
    CONSTRAINT pk_pay_stub PRIMARY KEY(`pay_stub_id`)
) COMMENT 'Transactional record representing the individual worker pay statement generated for each pay run, including full pay disbursement details. Captures worker identifier, pay run reference, gross pay, regular hours, overtime hours, double-time hours, per diem amounts, gross-to-net calculation details, total deductions, total tax withholdings, net pay, and stub status. Disbursement attributes: pay delivery method (direct deposit, check, pay card), check number or ACH trace number, bank routing number, account number (masked), account type (checking, savings), deposit allocation type (full net, fixed amount, percentage split), allocation amounts for split-deposit configurations, deposit priority for multiple accounts, prenote status, account verification status, and pay card routing for unbanked workers. SSOT for individual worker earnings per pay period, associated payment disbursement instructions, and banking configuration — consolidates all direct deposit and ACH details formerly tracked separately.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`pay_rate` (
    `pay_rate_id` BIGINT COMMENT 'Unique system-generated identifier for the pay rate record. Primary key for the pay_rate data product in the payroll domain.',
    `assignment_id` BIGINT COMMENT 'Reference to the worker assignment this pay rate applies to. Supports multi-rate scenarios where a worker may have different rates across concurrent assignments.',
    `burden_rate_id` BIGINT COMMENT 'Foreign key linking to payroll.burden_rate. Business justification: Pay rate structures should reference the master burden rate definition for accurate cost modeling and margin calculation. pay_rate currently has burden_rate_pct: DECIMAL(7,4) which is a denormalized v',
    `client_account_id` BIGINT COMMENT 'Reference to the client account for which the worker is placed. Used to validate rate alignment with client rate cards and MSA terms.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Pay rates are governed by MSA-negotiated rate schedules; critical for billing compliance, margin calculation, and audit trail. Staffing operations require tracing worker pay rates to governing client ',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Pay rates must align with contracted rate cards to ensure margin integrity and prevent billing disputes. Staffing operations require direct linkage for rate validation, markup verification, and client',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: Premium pay rates for licensed/certified workers (RN, CDL, PE) are validated against the specific active credential instance. Rate Validation by Active Credential Instance is a real staffing payroll',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Rate cards are tied to credential packages; different pay rates for workers with advanced certifications or security clearances. Healthcare staffing commonly pays premium rates for specialty certifica',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: Rate approval workflows validate that credential requirements are satisfied before activating pay rates; prevents paying workers who lack mandatory client-required credentials. Common in healthcare/IT',
    `direct_hire_id` BIGINT COMMENT 'Foreign key linking to placement.direct_hire. Business justification: Direct hire placements have negotiated salary rates that drive payroll processing. Links placement deal terms to payroll rate structure for accurate salary administration and cost tracking.',
    `hiring_decision_id` BIGINT COMMENT 'Foreign key linking to recruitment.hiring_decision. Business justification: Pay rate records implement the bill/pay rates authorized by the hiring decision. Payroll auditors and rate dispute resolution processes require direct traceability from the active pay_rate record to t',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC agreement specifies payment_rate and payment_structure that directly govern pay rate setup for IC contractors. Staffing HR pay rate configuration for IC workers must reference the IC agreement to v',
    `job_category_id` BIGINT COMMENT 'Foreign key linking to joborder.job_category. Business justification: Pay rates are benchmarked and structured by job category for market rate analysis, pay grade assignment, and pricing consistency across clients. Staffing firms maintain category-level pay rate tables ',
    `labor_category_id` BIGINT COMMENT 'Foreign key linking to timesheet.labor_category. Business justification: Staffing firms structure pay rates by labor category/skill level for rate card management and client billing. This link supports rate card configuration, prevailing wage compliance, and ensures pay ra',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Pay rates frequently vary by work location due to metro differentials, cost-of-living adjustments, and site-specific client agreements. Essential for accurate rate management and pricing by location i',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP managed programs govern markup caps and rate schedules (markup_cap_pct, target_ttf_days). Pay rate approval in MSP engagements requires tracing rates to the managed program for billing compliance ',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: Pay rates are established during onboarding process. Tracking which onboarding engagement set the rate supports audit trails, rate dispute resolution, and compliance verification that rates were prope',
    `order_header_id` BIGINT COMMENT 'Reference to the job order (requisition) associated with this pay rate. Enables rate traceability back to the originating client requisition.',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: Staffing firms set pay rates directly against position-level requirements (pay_rate_min/max defined per position). Multi-position orders require position-level rate traceability for pay compliance aud',
    `profile_id` BIGINT COMMENT 'Reference to the worker/candidate whose compensation this pay rate governs. Links pay rate to the individual worker record.',
    `rate_agreement_id` BIGINT COMMENT 'Foreign key linking to vendor.rate_agreement. Business justification: rate_agreement defines negotiated markup, pay rate bounds, and spread floors/ceilings with a supplier. pay_rate must reference the governing rate_agreement to enforce rate compliance, flag exceptions,',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: SOW/IC engagements have distinct pay rates (milestone, hourly IC rates). Payroll must compute and audit pay for SOW workers against the specific engagement terms. A staffing payroll expert would expec',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOWs define engagement-specific terms including pay rate structures and worker classifications. Staffing firms must link pay rates to SOWs for scope compliance, change order management, and SOW-level ',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Pay rates must meet state-specific minimum wage, prevailing wage, and overtime rules. Staffing firms link rate records to the governing state compliance rule to validate rates against jurisdictional m',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Staffing agencies use subcontractor vendors to fulfill placements when internal candidate pools are insufficient. Pay rates must track which vendor supplied the worker for vendor invoice reconciliatio',
    `vendor_rate_card_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor_rate_card. Business justification: pay_rate governs what a worker is paid; vendor_rate_card defines the supplier-negotiated pay/bill rates. Linking them enables rate card compliance auditing — verifying applied pay rates match the nego',
    `vms_program_id` BIGINT COMMENT 'Foreign key linking to client.vms_program. Business justification: VMS programs enforce markup and bill-rate caps (markup_cap_pct, bill_rate_cap_currency). Pay rate approval workflows must validate rates against VMS program caps. Staffing operations experts expect pa',
    `rate_id` BIGINT COMMENT 'External rate identifier assigned by the Vendor Management System (VMS), such as Beeline, when the rate is VMS-driven. Used for reconciliation between TempWorks Payroll and Beeline VMS rate management. Populated only when rate_source = vms_driven.',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Pay rates require validated wage/hour determinations for FLSA exemption status, prevailing wage compliance, and minimum wage validation. Staffing firms must document compliant rate approval before ass',
    `work_authorization_id` BIGINT COMMENT 'Foreign key linking to credentialing.work_authorization. Business justification: H1B/LCA prevailing wage compliance requires pay rates to be validated against work authorization type — staffing firms sponsoring visas must document Pay Rate Compliance by Work Authorization for DO',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: Pay rates vary by work location due to prevailing wage laws, state minimum wage, and shift differentials. pay_rate has location_id (→client.location) but placement.work_location carries workers_comp_c',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Pay rates are directly determined by worker classification (W-2 vs. 1099, FLSA exempt vs. non-exempt). Staffing firms must link rate records to the governing classification determination for FLSA comp',
    `approval_status` STRING COMMENT 'Current workflow state of the pay rate record. Pending = awaiting manager or compliance approval; approved = active and payroll-eligible; rejected = denied; expired = past effective end date. Controls whether the rate can be used in payroll processing.. Valid values are `pending|approved|rejected|expired`',
    `approved_by` STRING COMMENT 'Name or identifier of the manager, recruiter, or compliance officer who approved this pay rate. Provides audit trail for rate authorization in compliance with internal controls and OFCCP requirements.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the pay rate was formally approved. Part of the rate lifecycle audit trail. Required for SOC 2 Type II compliance and internal payroll controls.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The rate charged to the client for each unit of the workers time (typically per hour). Stored alongside the pay rate to enable spread and gross margin calculation. The spread (bill_rate minus regular_pay_rate) is the primary revenue metric in staffing. Sourced from the client rate card or VMS.',
    `conversion_fee_waiver_date` DATE COMMENT 'Date after which the clients conversion fee obligation is waived if the worker is converted to a permanent employee. Typically tied to a minimum number of hours worked or weeks on assignment per the MSA terms. Null if no conversion fee waiver applies.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the pay rate record was first created in TempWorks Payroll. Provides the audit trail creation anchor for SOC 2 Type II compliance and data lineage tracking in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which all monetary rate fields are denominated (e.g., USD, CAD, GBP). Supports multi-currency payroll for international staffing operations.. Valid values are `^[A-Z]{3}$`',
    `dt_rate_multiplier` DECIMAL(18,2) COMMENT 'Multiplier applied to the regular pay rate to calculate the double-time (DT) pay rate. Typically 2.0x, applicable in states such as California for hours over 12 in a day or on the 7th consecutive day. Applied by TempWorks Payroll for DT hours.',
    `effective_end_date` DATE COMMENT 'The date after which this pay rate is no longer active. Nullable for open-ended rates. When populated, payroll processing after this date must use a successor rate record. Supports rate versioning and assignment extensions.',
    `effective_start_date` DATE COMMENT 'The date from which this pay rate becomes active and applicable to payroll processing. Defines the beginning of the rates binding period. Payroll transactions on or after this date use this rate.',
    `fica_exempt` BOOLEAN COMMENT 'Indicates whether the worker is exempt from FICA (Social Security and Medicare) withholding for this assignment. True for certain visa holders (e.g., F-1, J-1 students) or specific worker classifications. Drives TempWorks Payroll tax withholding logic.',
    `flsa_exempt` BOOLEAN COMMENT 'Indicates whether the worker is classified as exempt from FLSA overtime requirements (True = exempt salaried; False = non-exempt hourly). Determines whether OT and DT multipliers apply. Critical for wage and hour compliance and DOL audit defense.',
    `is_blended_rate` BOOLEAN COMMENT 'Indicates whether this pay rate is a blended rate covering multiple job duties or skill levels within a single assignment. True = blended rate applies; False = single-role rate. Common in SOW engagements and multi-skill temporary placements.',
    `markup_pct` DECIMAL(18,2) COMMENT 'The percentage markup applied over the regular pay rate to arrive at the bill rate. Expressed as a decimal (e.g., 0.45 = 45% markup). Used for pricing analysis, margin reporting, and VMS rate negotiations. Markup = (bill_rate - regular_pay_rate) / regular_pay_rate.',
    `max_straight_time_hours` DECIMAL(18,2) COMMENT 'Maximum number of hours per week or pay period at the regular pay rate before overtime (OT) rates apply. Typically 40 hours per week under FLSA, but may be lower per client contract or state law (e.g., California daily OT threshold). Drives OT calculation trigger in TempWorks Payroll.',
    `min_guaranteed_hours` DECIMAL(18,2) COMMENT 'Minimum number of hours per pay period the worker is guaranteed to be paid, regardless of actual hours worked. Common in certain staffing contracts and SOW engagements. Impacts gross pay floor calculation in TempWorks Payroll.',
    `ot_rate_multiplier` DECIMAL(18,2) COMMENT 'Multiplier applied to the regular pay rate to calculate the overtime (OT) pay rate. Standard FLSA minimum is 1.5x for hours over 40 per week. May be higher per client contract or state law. Applied by TempWorks Payroll for OT hours on timesheets.',
    `pay_frequency` STRING COMMENT 'Frequency at which the worker is paid. Determines payroll cycle alignment in TempWorks Payroll. Weekly is most common for temporary staffing; bi-weekly and semi-monthly for salaried placements.. Valid values are `weekly|bi_weekly|semi_monthly|monthly`',
    `pay_grade` STRING COMMENT 'Internal compensation band or grade classification assigned to this pay rate (e.g., G1, G2, Band A). Used for workforce analytics, compensation equity analysis, and EEOC/OFCCP reporting on pay equity across worker populations.',
    `per_diem_rate` DECIMAL(18,2) COMMENT 'Daily non-taxable allowance paid to the worker for meals, lodging, and incidentals when working away from their tax home. Expressed in currency per day. Must comply with IRS per diem guidelines to maintain non-taxable status. Tracked separately from regular pay for tax reporting.',
    `pto_accrual_eligible` BOOLEAN COMMENT 'Indicates whether the worker accrues Paid Time Off (PTO) under this pay rate configuration. Eligibility may depend on assignment duration, worker classification, or client program rules. Drives PTO accrual processing in TempWorks Payroll.',
    `pto_accrual_rate` DECIMAL(18,2) COMMENT 'Rate at which PTO hours accrue per hour worked or per pay period, expressed in hours. For example, 0.0385 hours of PTO per hour worked equates to approximately 1 week of PTO per year. Populated only when pto_accrual_eligible = True.',
    `rate_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this pay rate configuration within TempWorks Payroll and Beeline VMS. Used for rate card lookups and VMS-driven rate matching.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_negotiation_notes` STRING COMMENT 'Free-text notes documenting the rationale, context, or special conditions behind the negotiated pay rate. May include references to candidate counter-offers, market data justifications, or client-specific rate exceptions. Supports recruiter and account manager context for future rate reviews.',
    `rate_source` STRING COMMENT 'Origin of the pay rate determination. Negotiated = individually agreed with worker; vms_driven = rate set by Vendor Management System (VMS) such as Beeline; standard = internal standard rate table; client_rate_card = derived from client-specific rate card agreement.. Valid values are `negotiated|vms_driven|standard|client_rate_card`',
    `rate_type` STRING COMMENT 'Classification of how the worker is compensated. Hourly = per hour worked; salary = fixed periodic amount; piece_rate = per unit produced; daily = per day worked. Drives gross pay calculation logic in TempWorks Payroll.. Valid values are `hourly|salary|piece_rate|daily`',
    `regular_pay_rate` DECIMAL(18,2) COMMENT 'The base pay rate for the worker expressed in the applicable rate_type unit (e.g., dollars per hour for hourly workers, dollars per day for daily workers). This is the principal quantitative compensation fact. Used as the basis for gross pay calculation in TempWorks Payroll.',
    `shift_differential_rate` DECIMAL(18,2) COMMENT 'Additional pay rate amount added to the regular pay rate for workers assigned to non-standard shifts (e.g., evening, overnight, weekend). Expressed as a flat dollar amount per hour or as a percentage add-on depending on the shift_differential_type field.',
    `shift_differential_type` STRING COMMENT 'Indicates whether the shift_differential_rate is a flat dollar amount added per hour or a percentage of the regular pay rate. Determines how TempWorks Payroll calculates the effective shift pay.. Valid values are `flat_amount|percentage`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this pay rate record originated. Supports data lineage, reconciliation, and conflict resolution in the Databricks Silver Layer when rates are ingested from multiple upstream systems.. Valid values are `tempworks|beeline_vms|bullhorn|manual`',
    `state_code` STRING COMMENT 'Two-letter US state code where the worker performs services under this pay rate. Determines applicable SUTA rate, state income tax withholding rules, state-specific overtime laws, and workers comp jurisdiction. Critical for multi-state payroll compliance.. Valid values are `^[A-Z]{2}$`',
    `suta_state_code` STRING COMMENT 'Two-letter state code designating the state to which SUTA (State Unemployment Tax Act) taxes are remitted for this worker. May differ from work state_code in multi-state scenarios or when the workers base state differs from the work location state.. Valid values are `^[A-Z]{2}$`',
    `temp_to_perm_eligible` BOOLEAN COMMENT 'Indicates whether the worker under this pay rate is eligible for conversion from temporary to permanent (temp-to-perm or contract-to-hire) placement. Affects conversion fee applicability and rate renegotiation triggers upon conversion.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the pay rate record was last modified. Tracks rate amendments, approval status changes, and effective date adjustments. Required for change data capture (CDC) in the Databricks Silver Layer pipeline.',
    `workers_comp_code` STRING COMMENT 'NCCI or state-specific workers compensation classification code associated with the job duties for this pay rate. Determines the workers comp insurance premium rate applied to the workers wages. Critical for accurate burden rate calculation and insurance compliance.',
    CONSTRAINT pk_pay_rate PRIMARY KEY(`pay_rate_id`)
) COMMENT 'Master record defining the pay rate structure for a worker on a specific assignment or job order. Captures regular pay rate, overtime (OT) rate multiplier, double-time (DT) rate multiplier, per diem rate, shift differential rate, effective start and end dates, rate type (hourly, salary, piece-rate, daily), pay frequency (weekly, bi-weekly, semi-monthly), currency, rate source (negotiated, VMS-driven, standard), and approval status. Supports multi-rate scenarios for workers on multiple assignments.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`earnings_line` (
    `earnings_line_id` BIGINT COMMENT 'Unique surrogate identifier for each individual earnings line item within a worker pay stub. Primary key for the earnings_line product in the payroll domain. TRANSACTION_LINE role — each record represents one earnings component (e.g., regular pay, OT, per diem) within a parent pay stub header.',
    `absence_record_id` BIGINT COMMENT 'Foreign key linking to timesheet.absence_record. Business justification: PTO and FMLA earnings lines must trace back to the approved absence record. Linking earnings_line.absence_record_id → timesheet.absence_record enables FMLA/PTO payroll audit trails and ensures paid le',
    `assignment_id` BIGINT COMMENT 'Reference to the placement assignment under which this earnings line was generated. Links the pay line to the specific client engagement, job order, and work location context in Bullhorn ATS/CRM. Enables earnings analysis by assignment, client, and job order.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Individual earnings must trace to contracted rate schedules for audit compliance and dispute resolution. Staffing operations require line-level validation that billed rates match contracted terms, esp',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: Time-to-pay processing validates credential status at earning line level; blocks payment for specific shifts worked without valid credentials (e.g., expired nursing license). Granular compliance enfor',
    `direct_hire_id` BIGINT COMMENT 'Foreign key linking to placement.direct_hire. Business justification: Direct hire placements generate earnings (salary, bonuses, adjustments). Links payroll earnings to permanent placement for fee reconciliation, guarantee period tracking, and revenue recognition valida',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC agreements payment_structure (milestone, hourly, fixed) and form_1099_reporting_flag govern how earnings lines are coded and reported for IC workers. IRS 1099-NEC reporting requires tracing each e',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: Individual earnings require traceability to the onboarding engagement that authorized the work arrangement. Essential for compliance audits verifying workers were properly onboarded before earning wag',
    `order_header_id` BIGINT COMMENT 'Foreign key linking to joborder.order_header. Business justification: Individual earnings lines require job order context for client billing detail, markup calculation per order terms, and granular job profitability analysis. Core to staffing agency revenue and cost tra',
    `original_line_earnings_line_id` BIGINT COMMENT 'Reference to the original earnings_line_id that this adjustment or correction line is reversing or modifying. Populated only when is_adjustment is True. Enables full audit trail of payroll corrections and supports prior-period adjustment reporting. Null for original (non-adjustment) earnings lines.',
    `pay_rate_id` BIGINT COMMENT 'Foreign key linking to payroll.pay_rate. Business justification: Each earnings line item is computed from a specific pay rate record (regular rate, OT multiplier, DT multiplier, per diem rate). Adding pay_rate_id to earnings_line links each gross pay component back',
    `pay_run_id` BIGINT COMMENT 'Identifier of the payroll processing run that generated this earnings line. Links to the payroll batch/run record in TempWorks Payroll. Used for payroll audit trails, reprocessing identification, and reconciliation of payroll runs against approved timesheets and pay stub totals.',
    `pay_stub_id` BIGINT COMMENT 'Foreign key reference to the parent pay stub (TRANSACTION_HEADER) that this earnings line belongs to. Satisfies HEADER_REFERENCE minimum category for TRANSACTION_LINE role. Links the line item to the workers gross-to-net pay stub record in TempWorks Payroll.',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: For orders with multiple position requirements at different pay rates, earnings lines must trace to the specific position for position-level payroll reconciliation, prevailing wage compliance reportin',
    `profile_id` BIGINT COMMENT 'Identifier of the worker (temporary associate, contractor, or permanent employee) whose earnings this line represents. Satisfies PARTY_REFERENCE minimum category. Links to the candidate/worker master record in Bullhorn ATS/CRM and SAP SuccessFactors.',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: SOW engagements generate earnings when worker is W-2 employee. Milestone or hourly SOW work creates payroll earnings that must link to engagement for billing reconciliation and cost tracking.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Earnings lines are computed under state-specific overtime thresholds, minimum wage floors, and prevailing wage rules. Staffing firms link earnings lines to the governing state compliance rule for stat',
    `time_entry_id` BIGINT COMMENT 'Foreign key linking to timesheet.time_entry. Business justification: Each earnings line is derived from one or more time entries. Linking earnings_line.time_entry_id → timesheet.time_entry enables payroll auditors to trace each earnings line to the specific punch recor',
    `timesheet_id` BIGINT COMMENT 'Reference to the approved timesheet record from which this earnings line was derived. Links payroll earnings back to the source time and attendance data captured in Kronos Workforce Ready. Null for non-hour-based earnings such as bonuses or expense reimbursements.',
    `training_record_id` BIGINT COMMENT 'Foreign key linking to credentialing.training_record. Business justification: Training pay earnings lines (orientation pay, mandatory training stipends) are directly triggered by completed training records. Training Pay Audit: Earnings Lines by Training Record is a real staff',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Each earnings line must comply with overtime rules, prevailing wage requirements, and FLSA classifications. Payroll systems validate earnings against wage/hour determinations to ensure compliant OT ca',
    `wc_policy_id` BIGINT COMMENT 'Foreign key linking to payroll.wc_policy. Business justification: Each earnings line carries a workers_comp_code (STRING) identifying the NCCI class applicable to that earnings component. Adding wc_policy_id to earnings_line links each pay component to the specific ',
    `work_location_id` BIGINT COMMENT 'Reference to the specific client work location where the worker performed services during this pay period. Used for workers compensation premium allocation by location, multi-state tax nexus determination, and client billing reconciliation. Links to the placement work location record.',
    `check_date` DATE COMMENT 'The date on which the workers paycheck or direct deposit is issued. Represents the principal business event date for this earnings line. Used for tax period determination (W-2 year allocation), cash flow reporting, and worker payment confirmation. Satisfies BUSINESS_EVENT_TIMESTAMP minimum category.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this earnings line record was first created in the payroll system. Satisfies RECORD_AUDIT_CREATED minimum category. Used for data lineage, audit trails, and SOC 2 Type II compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the monetary amounts on this earnings line. Defaults to USD for domestic US staffing operations. Relevant for international EOR (Employer of Record) arrangements and cross-border staffing engagements. Supports multi-currency payroll processing for global staffing operations.. Valid values are `^[A-Z]{3}$`',
    `earning_code` STRING COMMENT 'Standardized alphanumeric code identifying the type of earning component (e.g., REG for regular pay, OT for overtime, DT for double time, HOL for holiday, PTO for paid time off, BONUS, COMM for commission, PERDIEM, EXPREIM for expense reimbursement, SHFTDIFF for shift differential). Satisfies RESOURCE_REFERENCE minimum category as the classification key for the earning type resource. Drives tax treatment, GL account mapping, and compliance reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `earning_description` STRING COMMENT 'Human-readable description of the earning component as it appears on the workers pay stub. Examples: Regular Hours, Overtime Pay, Holiday Pay - Labor Day, PTO Payout, Weekly Per Diem - Chicago Assignment. Provides transparency to the worker and supports payroll audit trails.',
    `earning_type` STRING COMMENT 'Categorical classification of the earning component. Drives gross pay decomposition, tax withholding logic, and compliance reporting. Regular = straight-time wages; OT (Overtime) = FLSA-mandated 1.5x pay; DT (Double Time) = 2x pay per CBA or client agreement; PTO (Paid Time Off) = accrued leave payout; Per Diem = non-taxable daily allowance; Expense Reimbursement = accountable plan reimbursement. [ENUM-REF-CANDIDATE: regular|overtime|double_time|holiday|pto|bonus|commission|per_diem|expense_reimbursement|shift_differential|other — promote to reference product]',
    `flsa_exemption_status` STRING COMMENT 'FLSA overtime exemption classification for the worker on this earnings line. Non-exempt workers are entitled to OT pay at 1.5x for hours over 40/week. Exempt classifications (executive, administrative, professional, highly compensated) are not entitled to FLSA overtime. Drives overtime eligibility and compliance with DOL wage and hour regulations.. Valid values are `non_exempt|exempt_executive|exempt_administrative|exempt_professional|exempt_highly_compensated`',
    `gross_amount` DECIMAL(18,2) COMMENT 'Computed gross dollar amount for this earnings line, calculated as hours_quantity multiplied by pay_rate, or as a flat amount for non-hourly earnings. Represents the workers pre-tax, pre-deduction compensation for this specific earning component. Satisfies LINE_VALUE_OR_RESULT minimum category for TRANSACTION_LINE role. Feeds into gross pay totals on the pay stub.',
    `hours_quantity` DECIMAL(18,2) COMMENT 'Number of hours or units associated with this earnings line. For hour-based earnings (regular, OT, DT, holiday, PTO), this is the number of hours worked or paid. For unit-based earnings (piece rate, per diem days), this represents the unit count. Null for flat-amount earnings such as bonuses or expense reimbursements. Satisfies LINE_QUANTITY minimum category for TRANSACTION_LINE role.',
    `is_adjustment` BOOLEAN COMMENT 'Indicates whether this earnings line is a payroll adjustment or correction entry rather than an original earnings line. True for retroactive pay corrections, prior-period adjustments, and manual override entries. Adjustment lines may carry negative gross_amount values to reverse prior earnings. Used for payroll audit and SOX compliance.',
    `is_fica_subject` BOOLEAN COMMENT 'Indicates whether this earning component is subject to FICA (Federal Insurance Contributions Act) taxes, comprising Social Security (6.2%) and Medicare (1.45%) withholding. False for per diem reimbursements, expense reimbursements under accountable plans, and certain non-cash fringe benefits. Critical for accurate payroll tax calculation and IRS Form 941 filing.',
    `is_overtime` BOOLEAN COMMENT 'Indicates whether this earnings line represents overtime pay as defined under FLSA (Fair Labor Standards Act) — hours worked beyond 40 in a workweek compensated at a minimum of 1.5x the regular rate. Used for FLSA compliance reporting, overtime cost analytics, and client billing reconciliation where OT bill rates differ from straight-time rates.',
    `is_taxable` BOOLEAN COMMENT 'Indicates whether this earning component is subject to federal and state income tax withholding. True for wages, OT, DT, holiday pay, bonuses, and commissions. False for qualifying per diem allowances within IRS GSA limits, accountable plan expense reimbursements, and certain fringe benefits. Drives FICA, FUTA, SUTA, and income tax withholding calculations.',
    `labor_category_code` STRING COMMENT 'Classification code identifying the labor category or job classification for this earnings line (e.g., LIGHT_IND for light industrial, IT_PROF for IT professional, CLERICAL, HEALTHCARE). Used for workforce cost analytics, bill rate reconciliation, and compliance with prevailing wage determinations under DOL regulations. Aligns with timesheet.labor_category.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `line_sequence` STRING COMMENT 'Sequential line number ordering this earnings component within the parent pay stub. Satisfies LINE_SEQUENCE minimum category for TRANSACTION_LINE role. Used for display ordering on pay stubs and for deterministic processing order during gross pay calculation.',
    `line_status` STRING COMMENT 'Current processing status of this earnings line within the payroll workflow. Pending = awaiting payroll approval; Approved = authorized for payment; Processed = included in a completed payroll run; Voided = cancelled/reversed; Adjusted = corrected via an adjustment entry. Satisfies LIFECYCLE_STATUS minimum category for TRANSACTION_LINE role.. Valid values are `pending|approved|processed|voided|adjusted`',
    `ot_multiplier` DECIMAL(18,2) COMMENT 'The pay rate multiplier applied to the base pay rate for premium pay earnings. Standard values: 1.0000 for regular pay, 1.5000 for OT (overtime), 2.0000 for DT (double time). May reflect CBA (collective bargaining agreement) or client-specific premium rates. Used to validate gross_amount calculation and support FLSA compliance audits.',
    `pay_frequency` STRING COMMENT 'The frequency at which the worker is paid, determining the pay period structure for this earnings line. Weekly is most common for temporary staffing workers. Biweekly and semimonthly are common for permanent placements. Drives payroll processing schedule in TempWorks Payroll and tax withholding table selection.. Valid values are `weekly|biweekly|semimonthly|monthly`',
    `pay_period_end_date` DATE COMMENT 'Last calendar date of the pay period to which this earnings line applies. Defines the closing boundary of the work period being compensated. Used in conjunction with pay_period_start_date for FLSA overtime workweek calculations and state wage statement compliance.',
    `pay_period_start_date` DATE COMMENT 'First calendar date of the pay period to which this earnings line applies. Combined with pay_period_end_date, defines the work period being compensated. Critical for multi-state payroll compliance, FLSA overtime calculation, and tax period allocation.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly, daily, or unit rate applied to this earnings line to compute the gross amount. Represents the workers agreed compensation rate for this earning type (e.g., straight-time rate, OT rate at 1.5x, DT rate at 2x). Sourced from the placement rate agreement in Bullhorn ATS/CRM. Confidential as it contains worker compensation data.',
    `per_diem_rate_daily` DECIMAL(18,2) COMMENT 'The daily per diem rate applied for this earnings line when earning_type is per_diem. Compared against GSA (General Services Administration) published rates to determine taxability — amounts within GSA limits are non-taxable; excess amounts are taxable wages. Null for non-per-diem earning types.',
    `per_diem_type` STRING COMMENT 'Classification of per diem allowance type when earning_type is per_diem. Lodging = accommodation allowance; Meals and Incidentals (M&IE) = daily meal and incidental expense allowance; Combined = single daily rate covering both; None = not a per diem line. GSA per diem rates determine taxability thresholds. Null or none for non-per-diem earning types.. Valid values are `lodging|meals_incidentals|combined|none`',
    `prevailing_wage_flag` BOOLEAN COMMENT 'Indicates whether this earnings line is subject to prevailing wage requirements under the Davis-Bacon Act, Service Contract Act, or state prevailing wage laws. True for government contract assignments requiring certified payroll reporting. Triggers additional compliance reporting obligations to DOL and OFCCP.',
    `shift_code` STRING COMMENT 'Code identifying the work shift associated with this earnings line (e.g., DAY, EVE for evening, NIGHT, WKND for weekend). Used to apply shift differential pay rates and to reconcile earnings with Kronos Workforce Ready scheduling data. Relevant for shift_differential earning types.. Valid values are `^[A-Z0-9_]{1,10}$`',
    `source_system_ref` STRING COMMENT 'The native record identifier from the originating payroll system (TempWorks Payroll) for this earnings line. Enables traceability and reconciliation between the lakehouse silver layer and the operational system of record. Used for audit trails, data lineage, and dispute resolution.. Valid values are `^[A-Za-z0-9_-]{1,50}$`',
    `tax_year` STRING COMMENT 'The calendar tax year (YYYY) to which this earnings line is attributed for W-2 or 1099 reporting purposes. Determined by the check_date. Critical for year-end tax form preparation, IRS reporting, and multi-year payroll analytics. Enables accurate W-2 box 1 (wages) and 1099-NEC box 1 (nonemployee compensation) aggregation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this earnings line record was most recently modified. Satisfies RECORD_AUDIT_UPDATED minimum category. Tracks payroll corrections, status changes, and retroactive adjustments. Used for incremental data pipeline processing in the Databricks Lakehouse silver layer. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `work_state_code` STRING COMMENT 'Two-letter US state code where the work was performed for this earnings line. Drives state income tax withholding, SUTA (State Unemployment Tax Act) employer contributions, state-specific overtime rules, and workers compensation premium allocation. Critical for multi-state payroll compliance in staffing operations where workers may be deployed across multiple states.. Valid values are `^[A-Z]{2}$`',
    `worker_type` STRING COMMENT 'Tax and employment classification of the worker for this earnings line. W-2 Temp = temporary employee on agency payroll; W-2 Perm = permanent placed employee; 1099 IC (Independent Contractor) = self-employed contractor; EOR (Employer of Record) = worker employed through EOR arrangement. Determines tax withholding obligations, FICA applicability, FUTA/SUTA liability, and W-2 vs 1099 year-end tax form issuance.. Valid values are `w2_temp|w2_perm|1099_ic|eor`',
    `workers_comp_code` STRING COMMENT 'NCCI (National Council on Compensation Insurance) workers compensation class code applicable to this earnings line. Determines the workers comp insurance premium rate applied to the gross wages. Critical for accurate workers comp cost allocation, experience modification factor calculations, and compliance with state workers compensation insurance requirements.. Valid values are `^[0-9]{4,5}$`',
    CONSTRAINT pk_earnings_line PRIMARY KEY(`earnings_line_id`)
) COMMENT 'Transactional line-item record capturing each individual earnings component within a worker pay stub. Covers regular pay, OT pay, DT pay, holiday pay, PTO payout, bonus, commission, per diem, expense reimbursement, shift differential, and other earning types. Stores hours or units, rate applied, earning code, earning description, taxability flag, and computed gross amount. Enables granular gross pay decomposition for reporting and compliance.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`tax_line` (
    `tax_line_id` BIGINT COMMENT 'Primary key for tax_line',
    `original_tax_line_id` BIGINT COMMENT 'Reference to the original tax line record that this adjustment line corrects or reverses. Null for original (non-adjustment) lines. Enables audit trail linking between original and corrected tax line records.',
    `pay_run_id` BIGINT COMMENT 'Reference to the payroll processing run (batch) in which this tax line was computed. Supports reconciliation of all tax lines within a single payroll cycle.',
    `pay_stub_id` BIGINT COMMENT 'Reference to the parent pay stub (paycheck) that this tax line belongs to. Establishes the header/detail relationship between the pay stub and its individual tax line items. TRANSACTION_LINE HEADER_REFERENCE category.',
    `profile_id` BIGINT COMMENT 'Reference to the worker (W-2 employee or 1099 independent contractor) for whom this tax line is computed. TRANSACTION_LINE PARTY_REFERENCE category.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Tax lines are computed under state-specific tax rules (rates, wage bases, deposit schedules, SUTA experience rates). Staffing firms link tax lines to the governing state compliance rule for state tax ',
    `tax_filing_id` BIGINT COMMENT 'Foreign key linking to payroll.tax_filing. Business justification: Tax line records (individual tax obligations per pay stub) feed into aggregate tax filings (941, state quarterly filings). Adding FK tax_filing_id → tax_filing.payroll_tax_filing_id links each tax_lin',
    `tax_withholding_election_id` BIGINT COMMENT 'Foreign key linking to payroll.tax_withholding_election. Business justification: Tax withholding execution (tax_line) should reference the workers tax withholding election (W-4 form data) that drove the calculation. tax_line currently has denormalized attributes filing_status, al',
    `add_medicare_surtax_flag` BOOLEAN COMMENT 'Indicates whether this tax line represents the Additional Medicare Tax (0.9% surtax) applicable to high-earning employees whose wages exceed the IRS threshold ($200,000 for single filers). Employer does not match this surtax.',
    `adjustment_flag` BOOLEAN COMMENT 'Indicates whether this tax line is an adjustment or correction to a previously processed tax line (e.g., retroactive rate change, prior-period correction, amended return adjustment). When True, adjustment_reason should be populated.',
    `adjustment_reason` STRING COMMENT 'Free-text description of the reason for a tax line adjustment when adjustment_flag is True (e.g., Retroactive SUTA rate change Q1 2024, W-4 correction applied, Prior period underpayment correction).',
    `check_date` DATE COMMENT 'The date on which the paycheck or direct deposit was issued to the worker. Determines the tax deposit liability date and the calendar year to which the tax obligation is attributed for W-2 reporting purposes.',
    `computed_amount` DECIMAL(18,2) COMMENT 'The calculated tax dollar amount for this line in the current pay period (taxable_wage_base × tax_rate, or flat amount for flat-rate taxes). Core value used in gross-to-net calculation and payroll tax remittance. TRANSACTION_LINE LINE_VALUE_OR_RESULT category.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this tax line record was first created in the system. Supports audit trail, data lineage, and SOC 2 Type II compliance requirements. TRANSACTION_LINE RECORD_AUDIT_CREATED category.',
    `deposit_schedule` STRING COMMENT 'The employers IRS-assigned federal tax deposit schedule for this tax type (monthly, semi-weekly, or next-day for large deposits). Determines the tax_deposit_liability_date. State deposit schedules may differ.. Valid values are `monthly|semi_weekly|next_day|quarterly|annual`',
    `futa_credit_rate` DECIMAL(18,2) COMMENT 'The FUTA state tax credit rate (up to 5.4%) applied to reduce the gross FUTA rate of 6.0% when the employer has paid SUTA taxes in a credit-reduction state. Applies only to FUTA tax type lines.',
    `line_sequence` STRING COMMENT 'Sequential ordering number of this tax line within the parent pay stub. Enables deterministic ordering and display of all tax line items on a pay stub. TRANSACTION_LINE LINE_SEQUENCE category.',
    `pay_period_end_date` DATE COMMENT 'The last calendar date of the pay period to which this tax line applies. Together with pay_period_start_date, defines the exact payroll period for tax obligation accrual and filing.',
    `pay_period_start_date` DATE COMMENT 'The first calendar date of the pay period to which this tax line applies. Used for period-over-period tax reporting, quarterly filing (Form 941/940), and annual W-2 reconciliation.',
    `remittance_status` STRING COMMENT 'Current status of the tax remittance for this line to the applicable tax authority. Tracks whether the tax has been deposited on time, is pending, was remitted late (triggering penalty exposure), has been adjusted, or voided. TRANSACTION_LINE LIFECYCLE_STATUS category.. Valid values are `pending|remitted|late|adjusted|voided`',
    `source_system_record_code` STRING COMMENT 'The native record identifier from TempWorks Payroll (the system of record) for this tax line. Enables traceability and reconciliation between the lakehouse Silver layer and the operational payroll system.',
    `suta_experience_rate` DECIMAL(18,2) COMMENT 'The employers SUTA experience-rated tax rate for the applicable state, as assigned by the state unemployment agency based on the companys claims history. Applies only to SUTA tax type lines. Drives burden rate calculations.',
    `suta_state` STRING COMMENT 'Two-letter state code identifying the state to which SUTA taxes are remitted for this worker. May differ from the workers work state in multi-state assignments. Applies only to SUTA tax type lines.. Valid values are `^[A-Z]{2}$`',
    `tax_authority_level` STRING COMMENT 'Level of government authority imposing this tax obligation. Supports multi-state payroll compliance and jurisdiction-level tax filing and reporting.. Valid values are `federal|state|local|city|county`',
    `tax_deposit_liability_date` DATE COMMENT 'The date by which the employer must remit this tax to the applicable tax authority (IRS, state, or local). Determined by the employers deposit schedule (monthly or semi-weekly for federal; varies by state). Critical for avoiding late deposit penalties.',
    `tax_exempt_flag` BOOLEAN COMMENT 'Indicates whether the worker is exempt from this specific tax type (e.g., FICA exemption for certain visa holders, FUTA exemption for specific worker categories). When True, computed_amount is zero and the exemption basis should be documented.',
    `tax_exempt_reason` STRING COMMENT 'Reason or basis for the tax exemption when tax_exempt_flag is True (e.g., F-1 Visa FICA Exemption, W-4 Exempt Election, Agricultural Worker FUTA Exemption). Required for compliance audit trail.',
    `tax_jurisdiction_fips` STRING COMMENT 'Five-digit FIPS code uniquely identifying the county or county-equivalent jurisdiction for this tax line. Enables precise multi-state and local tax jurisdiction mapping and filing.. Valid values are `^[0-9]{5}$`',
    `tax_jurisdiction_locality` STRING COMMENT 'Name of the local taxing jurisdiction (city, county, municipality, school district) for local/city tax lines. Null for federal and state-level taxes. Supports local tax filing compliance.',
    `tax_jurisdiction_state` STRING COMMENT 'Two-letter U.S. state code (USPS abbreviation) for the state in which this tax obligation applies. Null for federal-only taxes. Critical for multi-state payroll tax filing and SUTA rate management.. Valid values are `^[A-Z]{2}$`',
    `tax_quarter` STRING COMMENT 'Calendar quarter (1–4) in which this tax line falls, derived from the check date. Used for quarterly payroll tax filing (IRS Form 941, FUTA Form 940, and state equivalents) and quarterly reconciliation.',
    `tax_rate` DECIMAL(18,2) COMMENT 'The effective tax rate (as a decimal fraction, e.g., 0.062000 for 6.2%) applied to the taxable wage base to compute the tax amount for this line. For flat-dollar taxes, this may be zero with the flat amount captured in computed_amount.',
    `tax_side` STRING COMMENT 'Discriminator indicating whether this tax line represents an employee-side withholding (deducted from worker gross pay) or an employer-side tax obligation (borne by the staffing company). Critical for gross-to-net calculation and burden rate validation. TRANSACTION_LINE LINE_VALUE_OR_RESULT category (discriminator).. Valid values are `employee|employer`',
    `tax_type_code` STRING COMMENT 'Standardized code identifying the specific type of tax obligation on this line (e.g., FIT, SIT, FICA_SS_EE, FICA_MED_EE, FICA_SS_ER, FICA_MED_ER, FUTA, SUTA, LOCAL, ADD_MED, SUPP). Used for tax filing, reporting, and reconciliation. [ENUM-REF-CANDIDATE: FIT|SIT|LOCAL|FICA_SS_EE|FICA_MED_EE|FICA_SS_ER|FICA_MED_ER|FUTA|SUTA|ADD_MED|SUPP — promote to reference product]',
    `tax_type_name` STRING COMMENT 'Human-readable name of the tax type (e.g., Federal Income Tax, California State Income Tax, FICA Social Security Employee, Federal Unemployment Tax). Displayed on pay stubs and tax reports.',
    `tax_year` STRING COMMENT 'Calendar year (e.g., 2024) to which this tax line is attributed for annual tax reporting, W-2/1099 issuance, and year-end reconciliation.',
    `taxable_wage_base` DECIMAL(18,2) COMMENT 'The portion of the workers gross wages subject to this specific tax in the current pay period, after applying any applicable wage base caps (e.g., Social Security wage base, FUTA/SUTA wage base limits). TRANSACTION_LINE LINE_QUANTITY category.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this tax line record was last modified. Tracks adjustments, corrections, and status changes for audit trail and data lineage purposes. TRANSACTION_LINE RECORD_AUDIT_UPDATED category.',
    `wage_base_annual_limit` DECIMAL(18,2) COMMENT 'The annual taxable wage base ceiling for this tax type (e.g., $168,600 for Social Security in 2024; $7,000 for FUTA). Once the workers YTD wages exceed this limit, no further tax is assessed for this tax type in the calendar year.',
    `wage_base_cap_reached` BOOLEAN COMMENT 'Indicates whether the worker has reached the annual taxable wage base ceiling for this tax type in the current calendar year. When True, no further tax is assessed for this tax type until the next calendar year reset.',
    `withholding_method` STRING COMMENT 'Method used to calculate the tax withholding for this line: percentage of taxable wages, flat dollar amount, IRS tax table lookup, supplemental flat rate, or exempt (no withholding). Drives the calculation logic applied in TempWorks Payroll.. Valid values are `percentage|flat|table|supplemental|exempt`',
    `worker_tax_form_type` STRING COMMENT 'Indicates whether the worker is classified as a W-2 employee (subject to withholding) or a 1099 independent contractor (IC) for this tax line. Drives which tax obligations apply and which annual tax form is issued. Aligns with IRS worker classification rules.. Valid values are `W-2|1099-NEC|1099-MISC`',
    `ytd_tax_amount` DECIMAL(18,2) COMMENT 'Cumulative tax amount withheld or assessed for this worker under this tax type from the start of the calendar year through and including this pay period. Critical for quarterly (941/940) and annual (W-2/1099) tax reconciliation and filing.',
    `ytd_taxable_wages` DECIMAL(18,2) COMMENT 'Cumulative taxable wages for this worker under this tax type from the start of the calendar year through and including this pay period. Used to enforce annual wage base limits and for W-2/1099 annual reconciliation.',
    CONSTRAINT pk_tax_line PRIMARY KEY(`tax_line_id`)
) COMMENT 'Transactional record capturing all payroll tax obligations — both employee withholdings and employer-side taxes — per worker per pay stub within a pay run. Employee side: federal income tax, state income tax, local/city tax, FICA Social Security and Medicare employee shares, additional Medicare surtax, and supplemental withholdings. Employer side: FICA Social Security and Medicare employer match, FUTA, SUTA by state, and local employer taxes. Stores tax side discriminator (employee/employer), tax authority jurisdiction, tax type code, taxable wage base, tax rate applied, withholding method (percentage, flat, table-based), computed amount, YTD taxable wages, YTD amount, and multi-state jurisdiction details. SSOT for ALL payroll tax line items — both employee withholdings and employer taxes are unified in this single product with a tax_side discriminator. Critical for gross-to-net calculation, burden rate validation, multi-state payroll tax filing, and quarterly/annual tax reconciliation.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`deduction_line` (
    `deduction_line_id` BIGINT COMMENT 'Unique system-generated identifier for each deduction line item on a worker pay stub. Primary key for the deduction_line product. Entity role: TRANSACTION_LINE — represents one deduction item within a payroll check/pay stub header.',
    `assignment_id` BIGINT COMMENT 'Foreign key linking to placement.assignment. Business justification: Garnishments and benefit deductions are applied in the context of a specific assignment. Assignment-level deduction audit reports and garnishment compliance (CCPA limits per assignment income) require',
    `pay_period_id` BIGINT COMMENT 'Foreign key linking to timesheet.pay_period. Business justification: deduction_line has pay_period_start_date/end_date as plain columns with no FK to the authoritative pay_period. Linking deduction_line.pay_period_id → timesheet.pay_period normalizes period reference f',
    `pay_run_id` BIGINT COMMENT 'Reference to the payroll processing run batch in which this deduction line was calculated and applied. Enables traceability of deductions back to a specific payroll cycle execution.',
    `pay_stub_id` BIGINT COMMENT 'Reference to the parent payroll check (pay stub) to which this deduction line belongs. TRANSACTION_LINE role: HEADER_REFERENCE — links this line to its parent payroll transaction header.',
    `profile_id` BIGINT COMMENT 'Reference to the worker (employee, temporary associate, or contractor) whose pay is being reduced by this deduction. Supports multi-worker payroll processing across W-2 and 1099 classifications.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Deduction permissibility varies by state (prohibited deductions, garnishment rules, benefit mandate requirements). Staffing firms link deduction lines to the governing state compliance rule for state ',
    `annual_limit_amount` DECIMAL(18,2) COMMENT 'Maximum dollar amount that may be withheld for this deduction type in a calendar year, as set by IRS regulations or plan rules (e.g., IRS 401k elective deferral limit, FSA annual contribution cap, HSA annual contribution limit). Used to automatically stop withholding once the limit is reached. Null for deductions with no annual cap.',
    `arrears_amount` DECIMAL(18,2) COMMENT 'Dollar amount of deduction that was missed in a prior pay period and is being carried forward for collection in a subsequent period. Common for garnishments when disposable earnings were insufficient to cover the full order amount, or for benefit premiums missed during a leave of absence. Zero if no arrears exist.',
    `benefit_carrier_name` STRING COMMENT 'Name of the insurance carrier or financial institution administering the benefit plan associated with this deduction (e.g., Aetna, MetLife, Fidelity Investments, WageWorks). Used for carrier remittance reconciliation and benefits vendor management. Null for non-benefit deductions.',
    `benefit_enrollment_status` STRING COMMENT 'Current enrollment status of the worker in the benefit plan driving this deduction. Determines whether premium withholding should be active. COBRA status indicates the worker is continuing coverage under COBRA after employment separation. Null for non-benefit deductions.. Valid values are `enrolled|terminated|pending|waived|cobra`',
    `benefit_plan_name` STRING COMMENT 'Name of the employer-sponsored benefit plan associated with this deduction (e.g., Aetna PPO Gold, Delta Dental Premier, VSP Vision Basic, Fidelity 401k Plan). Populated only for benefit-type deductions. Sourced from the benefit enrollment record and used for benefits administration reporting and carrier remittance.',
    `benefit_plan_type` STRING COMMENT 'Classification of the benefit plan type driving this deduction. Used to categorize benefit deductions for ACA reporting, W-2 Box 12 coding, and benefits analytics. Null for non-benefit deductions. [ENUM-REF-CANDIDATE: medical|dental|vision|401k|roth_401k|fsa|hsa|life|supplemental — 9 candidates stripped; promote to reference product]',
    `check_date` DATE COMMENT 'The date on which the paycheck containing this deduction was issued to the worker. Represents the actual payment date used for tax deposit timing, W-2 year assignment, and garnishment remittance deadlines. TRANSACTION_LINE role: BUSINESS_EVENT_TIMESTAMP (date precision).',
    `court_order_number` STRING COMMENT 'Official court case number or agency order reference for garnishment-type deductions (child support, tax levy, creditor garnishment). Required for legal compliance and remittance to the issuing court or agency. Null for non-garnishment deductions.',
    `coverage_tier` STRING COMMENT 'The coverage tier elected by the worker for this benefit plan, which determines the premium amount withheld. Applicable to medical, dental, and vision benefit deductions. Values: employee_only (single coverage), employee_spouse (worker plus spouse/domestic partner), employee_children (worker plus dependents), family (worker plus all dependents). Null for non-benefit deductions.. Valid values are `employee_only|employee_spouse|employee_children|family`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this deduction line record was first created in the source payroll system. Supports audit trail, data lineage, and Silver Layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the deduction amount (e.g., USD). Supports multi-currency payroll processing for international staffing operations and EOR (Employer of Record) arrangements.. Valid values are `^[A-Z]{3}$`',
    `deduction_amount` DECIMAL(18,2) COMMENT 'Dollar amount withheld from the workers gross pay for this deduction line in the current pay period. For benefit deductions, represents the employee premium contribution. For garnishments, represents the court-ordered withholding amount. TRANSACTION_LINE role: LINE_VALUE_OR_RESULT — the principal monetary fact for this line.',
    `deduction_category` STRING COMMENT 'Granular business category of the deduction used for benefits administration reporting, compliance, and analytics. Distinguishes benefit plan types (medical, dental, vision, 401k, FSA, HSA, life, supplemental) from garnishment subtypes (child_support, tax_levy, creditor_garnishment, student_loan) and other voluntary deductions. [ENUM-REF-CANDIDATE: medical|dental|vision|401k|roth_401k|fsa|hsa|life|supplemental|child_support|tax_levy|creditor_garnishment|student_loan|uniform|other — promote to reference product]',
    `deduction_code` STRING COMMENT 'Standardized alphanumeric code identifying the specific deduction type as configured in the payroll system (e.g., MED01, DENT01, 401K, GARNCS, UNIFEE). Maps to the deduction setup table in TempWorks Payroll and drives calculation rules, GL account mapping, and tax treatment.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `deduction_frequency` STRING COMMENT 'How often this deduction is applied to the workers paycheck. Drives whether the deduction is taken every pay period or on a specific schedule (e.g., some benefit premiums are taken only on first and third paycheck of the month for semimonthly payroll). [ENUM-REF-CANDIDATE: per_pay_period|weekly|biweekly|semimonthly|monthly|quarterly|annual|one_time — promote to reference product]',
    `deduction_name` STRING COMMENT 'Human-readable name of the deduction as it appears on the workers pay stub (e.g., Medical Insurance - Employee, Child Support Garnishment, 401(k) Contribution). Sourced from the deduction code setup in TempWorks Payroll.',
    `deduction_status` STRING COMMENT 'Current lifecycle status of this deduction line: active (currently being withheld), suspended (temporarily halted, e.g., worker on leave), terminated (permanently stopped, e.g., benefit cancelled or garnishment satisfied), pending (set up but not yet effective), waived (worker or employer elected to waive for this period). TRANSACTION_LINE role: maps to LIFECYCLE_STATUS of the deduction arrangement.. Valid values are `active|suspended|terminated|pending|waived`',
    `deduction_type` STRING COMMENT 'Classification of the deduction by tax treatment and origin: pre_tax (reduces taxable gross, e.g., 401k, FSA, HSA, Section 125 benefits), post_tax (applied after tax calculation, e.g., Roth 401k, after-tax life insurance), benefit (employer-sponsored benefit premium withholding), garnishment (court-ordered or agency-mandated wage withholding), voluntary (worker-elected non-benefit deduction). Drives gross-to-net calculation sequencing.. Valid values are `pre_tax|post_tax|benefit|garnishment|voluntary`',
    `effective_date` DATE COMMENT 'Date on which this deduction arrangement became active for the worker. For benefit deductions, aligns with the benefit enrollment effective date. For garnishments, aligns with the court order service date. Determines when withholding begins.',
    `employer_contribution_amount` DECIMAL(18,2) COMMENT 'Dollar amount contributed by the employer toward this benefit deduction in the current pay period (e.g., employer share of medical premium, employer 401k match). Applicable only to benefit-type deductions. Zero or null for garnishments and purely employee-funded deductions. Used in total compensation reporting and burden rate calculations.',
    `enrollment_effective_date` DATE COMMENT 'Date on which the workers benefit enrollment became effective, triggering the start of premium withholding for this deduction. May differ from the deduction effective_date if there is a retroactive enrollment adjustment. Null for non-benefit deductions.',
    `enrollment_termination_date` DATE COMMENT 'Date on which the workers benefit enrollment ended, triggering cessation of premium withholding. Populated when a worker loses eligibility, voluntarily cancels coverage, or separates from employment. Null if enrollment is ongoing. Null for non-benefit deductions.',
    `garnishment_issuing_agency` STRING COMMENT 'Name of the court, government agency, or child support enforcement agency that issued the garnishment order (e.g., Cook County Circuit Court, IRS, Illinois DCSS). Used for remittance routing and compliance documentation. Null for non-garnishment deductions.',
    `garnishment_remittance_date` DATE COMMENT 'Date by which the withheld garnishment amount must be remitted to the issuing court or agency. Derived from the court order terms and state-specific remittance deadlines. Null for non-garnishment deductions.',
    `is_arrears_recovery` BOOLEAN COMMENT 'Indicates whether this deduction line represents a recovery of a previously missed (arrears) deduction amount rather than a standard current-period deduction. True when the deduction_amount includes or consists entirely of arrears recovery. Used to distinguish regular deductions from catch-up withholdings in payroll analytics.',
    `is_fica_exempt` BOOLEAN COMMENT 'Indicates whether this deduction amount is exempt from FICA (Social Security and Medicare) taxes. True for qualified Section 125 benefit deductions and HSA employer contributions. False for most other deductions. Drives FICA taxable wage base calculation in payroll processing.',
    `is_pretax` BOOLEAN COMMENT 'Indicates whether this deduction reduces the workers taxable gross wages before FICA, federal income tax, and applicable state income tax are calculated. True for Section 125 cafeteria plan deductions (medical, dental, vision, FSA), traditional 401k contributions, and HSA contributions. False for post-tax deductions such as Roth 401k and after-tax life insurance. Critical for accurate gross-to-net payroll calculation.',
    `line_sequence` STRING COMMENT 'Sequential ordering number of this deduction line within the parent paycheck. Enables ordered display of deductions on pay stubs and supports reconciliation of multiple deductions per pay period. TRANSACTION_LINE role: LINE_SEQUENCE.',
    `source_system` STRING COMMENT 'Operational system of record from which this deduction line record originated. Primarily TempWorks Payroll for payroll-processed deductions, SAP SuccessFactors for benefit enrollment-driven deductions, or manual for corrections entered directly. Supports data lineage and reconciliation in the Databricks Silver Layer.. Valid values are `tempworks|sap_successfactors|manual|beeline`',
    `termination_date` DATE COMMENT 'Date on which this deduction arrangement was or is scheduled to be permanently stopped. For benefit deductions, aligns with benefit enrollment termination or coverage end date. For garnishments, the date the order is satisfied or released. Null if the deduction is ongoing with no defined end.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this deduction line record was last modified in the source payroll system (e.g., amount correction, status change, suspension). Supports change data capture (CDC) processing in the Databricks Silver Layer and audit trail requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `w2_box_code` STRING COMMENT 'IRS W-2 form box code under which this deduction amount must be reported at year-end (e.g., D for 401k elective deferrals, W for HSA employer contributions, DD for employer-sponsored health coverage cost). Drives W-2 generation in TempWorks Payroll. Null for deductions not reportable on W-2.. Valid values are `^[A-Z]{1,2}$`',
    `work_state_code` STRING COMMENT 'Two-letter U.S. state code for the state in which the worker performed services during this pay period. Determines applicable state income tax withholding rules, state-specific garnishment limits, SUTA taxability, and state benefit deduction regulations. Critical for multi-state payroll compliance.. Valid values are `^[A-Z]{2}$`',
    `ytd_deduction_amount` DECIMAL(18,2) COMMENT 'Cumulative total of this deduction withheld from the workers pay from the start of the calendar year through and including the current pay period. Used for W-2 reporting, IRS annual contribution limit enforcement (e.g., 401k IRS limit, FSA/HSA annual caps), and year-end tax reconciliation.',
    CONSTRAINT pk_deduction_line PRIMARY KEY(`deduction_line_id`)
) COMMENT 'Transactional line-item record for each voluntary or involuntary deduction applied to a worker pay stub, serving as the SSOT for all payroll deductions including benefit enrollment-driven withholdings. For benefit-type deductions: stores benefit plan name, plan type (medical, dental, vision, 401k, FSA, HSA, life, supplemental), coverage tier (employee only, employee+spouse, family), employee premium contribution, employer contribution, benefit carrier, enrollment effective and termination dates, and enrollment status. For garnishment-type deductions: references the governing garnishment order. For all deductions: stores deduction code, deduction type (pre-tax, post-tax, benefit, garnishment), deduction amount, deduction frequency, YTD deduction total, court order reference for garnishments, and deduction status (active, suspended, terminated). Consolidates benefit enrollment tracking with deduction processing — enrollment attributes drive premium withholding calculations each pay period.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`burden_rate` (
    `burden_rate_id` BIGINT COMMENT 'Unique system-generated identifier for the burden rate record. Primary key for the burden_rate data product in the payroll domain.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account for which this burden rate is specifically configured, when applicability_scope is client_specific. Null for enterprise-wide or assignment-specific rates. Links to the client account master in the CRM.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Burden rates (FICA, SUTA, workers comp) are negotiated in MSAs and determine employer cost structure. Staffing firms must link burden to MSA for accurate gross margin calculation, client billing, and',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Burden rates in staffing are differentiated by credential package — healthcare credential packages carry different WC rates, liability loads, and compliance costs than light industrial. Burden Rate A',
    `job_category_id` BIGINT COMMENT 'Foreign key linking to joborder.job_category. Business justification: Burden rates (SUTA, WC, FICA) vary materially by job category (e.g., construction vs. clerical). Staffing firms maintain category-specific burden rate tables for accurate cost modeling and bid pricing',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Workers comp rates, SUTA rates, and employer burden vary significantly by work location and state jurisdiction. Required for accurate cost modeling, pricing, and margin analysis by client location in',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: EOR and MSP managed programs (is_eor_model, is_peo_model flags on burden_rate) require program-level burden rate governance. Program cost reporting and margin analysis depend on linking burden rates t',
    `order_header_id` BIGINT COMMENT 'Foreign key linking to joborder.order_header. Business justification: Burden rates can be order-specific when negotiated client terms, special insurance requirements, or custom rate cards apply. Supports accurate order-level cost modeling, pricing validation, and margin',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: Burden rates can differ by position within the same order (e.g., different WC codes for mixed-skill positions). Staffing firms calculate burden at position level for accurate gross margin analysis and',
    `primary_ot_burden_rate_id` BIGINT COMMENT 'Reference to the burden rate record applicable to overtime (OT) hours for this worker classification and state. Overtime pay triggers different FICA and WC cost calculations. Null if the same burden rate applies to both regular and OT hours.',
    `rate_agreement_id` BIGINT COMMENT 'Foreign key linking to vendor.rate_agreement. Business justification: burden_rate computes employer burden components (FICA, FUTA, SUTA, WC) for supplier-placed workers. rate_agreement defines the markup and burden-inclusive pricing negotiated with the supplier. Linking',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Burden rates include state-mandated costs (SUTA rates, workers comp rates, paid leave mandates) that vary by state compliance rule. Linking burden_rate to state_compliance_rule supports state-specifi',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Vendor-supplied workers often have different burden rates (FICA, SUTA, workers comp) due to co-employment, PEO models, or vendor-specific insurance policies. Accurate cost modeling and bill rate calc',
    `tertiary_superseded_by_burden_rate_id` BIGINT COMMENT 'Reference to the burden rate record that replaced this record when status is superseded. Enables forward navigation in the rate version chain for audit and historical analysis.',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Vendor agreements markup_cap_percentage directly constrains burden rate calculations for supplier-provided workers. Staffing finance teams validate burden rates against vendor agreement markup caps d',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Burden rates incorporate wage-hour determination outcomes including prevailing wage rates, OT multipliers, and minimum wage floors. Staffing firms link burden calculations to the governing wage-hour d',
    `wc_policy_id` BIGINT COMMENT 'Foreign key linking to payroll.wc_policy. Business justification: Burden rate calculations include workers compensation premium components that are defined by specific WC policies. burden_rate currently has wc_policy_number: STRING which is a denormalized reference.',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: Workers comp rates, SUTA rates, and burden components vary by work location due to state jurisdiction and site hazard classification. Links burden structure to location for accurate cost modeling.',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Burden rates differ fundamentally by worker classification: FICA, FUTA, SUTA apply only to W-2 employees. Staffing firms must link burden rate records to the compliance classification determination to',
    `applicability_scope` STRING COMMENT 'Defines the scope at which this burden rate is applied: enterprise_wide (default for all placements), client_specific (negotiated rate for a specific client account), assignment_specific (applied to a single placement or assignment), or branch_specific (applicable to a specific branch or division).. Valid values are `enterprise_wide|client_specific|assignment_specific|branch_specific`',
    `approved_date` DATE COMMENT 'Date on which this burden rate structure was formally approved by the authorized approver. Required for audit trail and SOC 2 change management compliance.',
    `benefits_load_percent` DECIMAL(18,2) COMMENT 'Employer-paid benefits cost expressed as a percentage of gross wages included in the burden rate. Covers health insurance, dental, vision, 401(k) match, and other statutory or voluntary benefits provided to workers. Varies by worker classification and benefit plan enrollment.',
    `branch_code` STRING COMMENT 'Code identifying the staffing branch or division to which this burden rate applies when applicability_scope is branch_specific. Supports multi-branch operations where burden structures differ by geographic market or business unit.. Valid values are `^[A-Z0-9]{2,10}$`',
    `burden_rate_status` STRING COMMENT 'Current lifecycle status of the burden rate record. active indicates the rate is in use for payroll cost calculations; superseded indicates a newer version has replaced this record; draft indicates pending approval before activation.. Valid values are `active|inactive|pending|superseded|draft`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this burden rate record was first created in the system. Supports audit trail, data lineage, and SOC 2 Type II compliance requirements.',
    `effective_date` DATE COMMENT 'Date from which this burden rate structure becomes effective and is applied to payroll cost calculations, spread analysis, and bill rate margin validation. Aligns with payroll period start dates.',
    `employment_type` STRING COMMENT 'Type of staffing engagement to which this burden rate applies. Temporary and contract placements typically carry higher WC and benefits burden; direct hire placements may carry only a placement fee structure. Temp-to-perm engagements may have conversion fee implications.. Valid values are `temporary|contract|temp_to_perm|direct_hire|per_diem`',
    `expiration_date` DATE COMMENT 'Date on which this burden rate structure ceases to be effective. Null indicates an open-ended rate with no scheduled expiration. Used to enforce rate versioning and ensure correct rate application during payroll processing.',
    `fica_employer_rate` DECIMAL(18,2) COMMENT 'Employers share of FICA tax expressed as a percentage of gross wages (e.g., 7.6500 for 7.65%). Comprises Social Security (6.2%) and Medicare (1.45%) employer contributions. Applied to gross pay up to applicable wage bases per IRS regulations.',
    `futa_rate` DECIMAL(18,2) COMMENT 'Federal Unemployment Tax Act employer tax rate expressed as a percentage of gross wages (e.g., 0.6000 for 0.60% net after state credit). Applied to the first $7,000 of each employees wages per calendar year per IRS regulations.',
    `general_liability_rate` DECIMAL(18,2) COMMENT 'General liability insurance cost expressed as a percentage of gross payroll included in the employer burden structure. Covers third-party bodily injury and property damage claims arising from staffing operations.',
    `is_eor_model` BOOLEAN COMMENT 'Indicates whether this burden rate applies to an Employer of Record (EOR) engagement model where the staffing firm acts as the legal employer of record for co-employment or client-directed workforce arrangements. EOR models carry distinct burden and compliance obligations.',
    `is_peo_model` BOOLEAN COMMENT 'Indicates whether this burden rate applies to a Professional Employer Organization (PEO) co-employment model where the PEO assumes employer tax and benefits obligations. PEO burden structures differ from standard staffing burden rates.',
    `markup_percent` DECIMAL(18,2) COMMENT 'Target markup percentage applied over the pay rate to derive the bill rate, incorporating the total burden and desired gross margin. Used in spread analysis and client billing validation. Expressed as a percentage of pay rate (e.g., 45.00 = 45% markup).',
    `notes` STRING COMMENT 'Free-text field for payroll analysts or finance staff to document special conditions, exceptions, carrier negotiation details, or regulatory basis for this burden rate configuration. Supports audit documentation and knowledge transfer.',
    `overhead_percent` DECIMAL(18,2) COMMENT 'Internal overhead allocation expressed as a percentage of gross wages included in the burden rate. Covers branch operating costs, recruiter commissions, back-office administration, and other indirect costs attributable to workforce deployment.',
    `pay_rate_max` DECIMAL(18,2) COMMENT 'Maximum hourly pay rate threshold (in USD) at which this burden rate structure is applicable. Defines the upper bound of the pay rate band for this burden rate. Null indicates no upper limit.',
    `pay_rate_min` DECIMAL(18,2) COMMENT 'Minimum hourly pay rate threshold (in USD) at which this burden rate structure is applicable. Used to define pay rate banding for tiered burden rate structures where different pay levels carry different overhead or benefits loads.',
    `rate_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this burden rate structure (e.g., BR-CA-WC-5403-2024). Used in billing systems, VMS integrations, and rate card references.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `rate_name` STRING COMMENT 'Human-readable descriptive name for the burden rate structure (e.g., California Light Industrial WC Class 5403 2024). Used in reporting, dashboards, and analyst-facing tools.',
    `rate_source` STRING COMMENT 'Origin of the burden rate values indicating how the rate was established: manual (entered by payroll/finance staff), system_calculated (derived by TempWorks Payroll engine), carrier_provided (supplied by WC or GL insurance carrier), or state_mandated (set by state regulatory authority).. Valid values are `manual|system_calculated|carrier_provided|state_mandated`',
    `rate_type` STRING COMMENT 'Classification of the burden rate structure indicating its scope of applicability: standard (default enterprise-wide), client_specific (negotiated for a client), assignment_specific (tied to a single placement), state_override (state-level regulatory override), or wc_class_specific (Workers Compensation class-driven rate).. Valid values are `standard|client_specific|assignment_specific|state_override|wc_class_specific`',
    `state_code` STRING COMMENT 'Two-letter U.S. state code (ISO 3166-2:US) identifying the state jurisdiction to which this burden rate applies. Critical for multi-state payroll compliance, SUTA rate assignment, and state-specific Workers Compensation rate overrides.. Valid values are `^[A-Z]{2}$`',
    `suta_rate` DECIMAL(18,2) COMMENT 'State Unemployment Tax Act employer contribution rate expressed as a percentage of gross wages for the applicable state jurisdiction. Varies by state experience rating, industry classification, and annual state-assigned rate notices. Applied to state-specific taxable wage bases.',
    `suta_wage_base` DECIMAL(18,2) COMMENT 'Maximum annual gross wages per employee subject to SUTA tax in the applicable state jurisdiction (e.g., $7,000 in some states, $56,500 in others). Required for accurate SUTA cost modeling and burden rate calculation.',
    `target_gross_margin_percent` DECIMAL(18,2) COMMENT 'Target gross margin percentage for placements using this burden rate structure, representing the desired spread (bill rate minus total employer cost) as a percentage of bill rate. Used in profitability reporting and bill rate validation.',
    `total_burden_percent` DECIMAL(18,2) COMMENT 'Aggregate employer burden rate expressed as a percentage of gross wages, representing the sum of all burden components (FICA employer share, FUTA, SUTA, WC, general liability, benefits load, and overhead). Used to compute total employer cost per worker hour and validate bill rate margins. Note: this is a stored configuration value, not a real-time computed aggregate.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this burden rate record was last modified. Used for change tracking, incremental data pipeline processing, and SOC 2 audit trail requirements.',
    `version_number` STRING COMMENT 'Sequential version number for this burden rate record, incremented each time the rate structure is updated. Supports rate versioning and historical rate lookups for payroll audits and retroactive adjustments.',
    `wc_base_rate_per_100` DECIMAL(18,2) COMMENT 'Workers Compensation insurance premium base rate expressed as dollars per $100 of gross payroll for the applicable NCCI class code and state jurisdiction (e.g., 2.3500 = $2.35 per $100). This is the primary WC cost driver in the burden rate structure.',
    `wc_class_description` STRING COMMENT 'Human-readable description of the NCCI Workers Compensation class code (e.g., Carpentry — Construction, Clerical Office Employees). Used in reporting, audits, and WC policy documentation.',
    `wc_experience_mod_factor` DECIMAL(18,2) COMMENT 'Experience modification factor (e-mod) applied to the WC base rate to adjust premiums based on the employers actual loss history relative to industry average. Values below 1.0 indicate better-than-average loss history; above 1.0 indicates worse. Sourced from WC carrier or NCCI.',
    `wc_hazard_category` STRING COMMENT 'Risk hazard category assigned to the WC NCCI class code indicating the relative injury risk level of the job duties. Used for internal risk segmentation, pricing decisions, and WC carrier negotiations.. Valid values are `low|medium|high|very_high`',
    `wc_ncci_class_code` STRING COMMENT 'Four-digit NCCI Workers Compensation classification code identifying the job duty category for WC premium calculation (e.g., 5403 for Carpentry, 8810 for Clerical Office). Drives WC base rate per $100 of payroll and is the primary driver of WC cost in staffing operations.. Valid values are `^[0-9]{4}$`',
    CONSTRAINT pk_burden_rate PRIMARY KEY(`burden_rate_id`)
) COMMENT 'Master record defining the employer burden rate structure applied to worker pay for cost modeling, spread calculation, and client billing markup in staffing operations. Captures burden components including FICA employer share percentage, FUTA rate, SUTA rate by state, workers compensation (WC) rate by NCCI class code (with state-specific overrides, class description, hazard category, and base rate per $100 of payroll), general liability rate, benefits load percentage, overhead percentage, and total burden percentage. Stores effective dates, state jurisdiction, WC policy reference, client or assignment applicability, and rate source (manual, system-calculated, carrier-provided). Used to compute total employer cost per worker hour, validate bill rate margins, and support spread analysis for staffing profitability reporting.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`wc_policy` (
    `wc_policy_id` BIGINT COMMENT 'Primary key for wc_policy',
    `client_account_id` BIGINT COMMENT 'Foreign key linking to client.client_account. Business justification: In co-employment and EOR arrangements, workers comp policies may be client-specific or shared across clients. Essential for risk management, premium allocation, and determining coverage responsibilit',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Workers comp policies are MSA-level insurance obligations; MSAs specify minimum coverage requirements. Staffing firms must link WC policies to MSAs for compliance verification, certificate of insuran',
    `job_category_id` BIGINT COMMENT 'Foreign key linking to joborder.job_category. Business justification: Workers comp policies are assigned by NCCI class code which maps directly to job category. Staffing firms assign WC policies per job category for premium calculation and audit compliance. wc_class_co',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Workers comp policies are jurisdiction-specific and tied to specific work locations. Required for accurate premium calculation, state compliance, and tracking which client locations are covered under',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: In EOR and co-employment MSP programs (co_employment_flag, eor_flag on wc_policy), workers comp policies are program-level constructs. Program-level WC insurance compliance reporting and premium allo',
    `pay_run_id` BIGINT COMMENT 'Foreign key linking to payroll.pay_run. Business justification: Workers compensation premium calculations are tied to specific payroll runs. wc_policy currently has pay_run_reference: STRING which is a denormalized reference. Adding structured FK pay_run_id → pay_',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Workers comp policies are governed by state-specific rules covering mandatory coverage thresholds, rate schedules, and exemptions. Staffing firms link WC policies to the governing state compliance ru',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Workers comp policies for vendor-supplied workers are often held by the vendor, not the staffing agency. Certificate of insurance (COI) tracking, premium audit, and liability determination require li',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Vendor agreement specifies workers_comp_minimum_usd as a contractual requirement for supplier workers. WC policy compliance validation for supplier-provided workers requires referencing the vendor agr',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: Workers compensation policies are issued per work location and jurisdiction. Each site has specific WC class codes and rates. Links policy coverage to physical work location.',
    `audit_adjustment_amount` DECIMAL(18,2) COMMENT 'The dollar amount of premium adjustment resulting from the most recent carrier audit, representing the difference between estimated premiums paid and actual earned premium based on audited payroll. Positive values indicate additional premium owed; negative values indicate a return premium credit.',
    `audit_frequency` STRING COMMENT 'The frequency at which the insurance carrier conducts a premium audit to reconcile estimated premiums against actual payroll. Staffing firms with high payroll volume often negotiate more frequent audits to reduce year-end true-up exposure.. Valid values are `annual|semi_annual|quarterly|monthly|continuous`',
    `base_rate_per_100` DECIMAL(18,2) COMMENT 'The manual (base) WC premium rate expressed as a dollar amount per $100 of covered payroll for the associated class code and state jurisdiction, before application of the experience modification factor (EMR). Sourced from the applicable state rating bureau or NCCI.',
    `burden_rate_wc_component` DECIMAL(18,2) COMMENT 'The WC premium cost expressed as a decimal rate applied to gross payroll, representing the WC component of the total employer burden rate. Used in bill rate calculations, spread analysis, and gross margin reporting. Derived from the modified rate and historical payroll mix for this class code.',
    `carrier_naic_code` STRING COMMENT 'The five-digit NAIC company code assigned to the insurance carrier by the National Association of Insurance Commissioners. Used for regulatory identification and carrier verification in multi-state WC compliance.. Valid values are `^[0-9]{5}$`',
    `carrier_name` STRING COMMENT 'The legal name of the insurance carrier or underwriter providing the workers compensation coverage under this policy. Used for carrier reporting, premium remittance, and audit correspondence.',
    `client_cost_allocation_code` STRING COMMENT 'The internal cost allocation code used to attribute WC premium costs to specific client accounts or job orders. Enables client-level WC cost reporting, profitability analysis, and accurate bill rate construction inclusive of WC burden.',
    `co_employment_flag` BOOLEAN COMMENT 'Indicates whether this WC policy record involves a co-employment arrangement where both the staffing firm and the client share employer responsibilities. Affects WC coverage determination and premium allocation between parties.',
    `computed_premium_amount` DECIMAL(18,2) COMMENT 'The calculated WC premium dollar amount for the premium period, computed as (payroll_subject_to_wc / 100) multiplied by the modified_rate_per_100. Represents the accrued WC cost for the period and is used in burden rate application and client cost allocation.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this workers compensation policy record was first created in the payroll system. Provides audit trail for record provenance and data lineage in the Databricks Silver Layer.',
    `deductible_amount_per_claim` DECIMAL(18,2) COMMENT 'The per-claim deductible amount the employer is responsible for funding before the carrier pays WC benefits, applicable to large deductible programs. Zero for guaranteed cost policies. Impacts cash flow planning and loss reserve requirements.',
    `deposit_premium_amount` DECIMAL(18,2) COMMENT 'The initial deposit premium paid to the carrier at policy inception, typically a percentage of the estimated annual premium. Represents the upfront cash outlay and is reconciled against actual earned premium at audit.',
    `effective_date` DATE COMMENT 'The date on which the workers compensation insurance policy becomes active and coverage begins. Used to determine coverage applicability for worker assignments and premium period calculations.',
    `employer_liability_limit_disease_policy` DECIMAL(18,2) COMMENT 'The aggregate policy limit of employers liability coverage for bodily injury by disease. Distinct from the per-accident limit and the per-employee disease limit. Used for risk management reporting and MSA compliance verification.',
    `employer_liability_limit_each_accident` DECIMAL(18,2) COMMENT 'The per-occurrence limit of employers liability coverage (Part B of the WC policy) for bodily injury by accident. Standard limits are $100,000, $500,000, or $1,000,000. Used for risk management and client contract compliance.',
    `eor_flag` BOOLEAN COMMENT 'Indicates whether this WC policy record applies to workers placed under an Employer of Record (EOR) arrangement, where the staffing firm acts as the legal employer for WC purposes. Drives co-employment risk management and premium allocation logic.',
    `estimated_annual_premium` DECIMAL(18,2) COMMENT 'The estimated total annual WC premium for this policy as projected at policy inception, based on estimated payroll and applicable rates. Used for budgeting, cash flow planning, and comparison against actual accrued premiums during the audit cycle.',
    `experience_mod_factor` DECIMAL(18,2) COMMENT 'The experience modification rate (EMR) assigned by NCCI or the applicable state rating bureau, reflecting the employers actual loss history relative to expected losses for the class. A factor below 1.0 indicates better-than-average loss experience; above 1.0 indicates worse. Applied to the base rate to compute the modified premium rate.',
    `expiration_date` DATE COMMENT 'The date on which the workers compensation insurance policy expires and coverage ends. Triggers renewal workflow and is used to validate coverage during assignment management and payroll processing.',
    `last_audit_date` DATE COMMENT 'The date of the most recently completed premium audit conducted by the insurance carrier. Used to track audit cycle compliance, identify overdue audits, and reconcile estimated versus actual premium balances.',
    `loss_sensitive_program_type` STRING COMMENT 'For loss-sensitive policies, identifies the specific program structure. Retrospective rated programs adjust final premium based on actual losses; large deductible programs require the employer to fund losses up to a deductible threshold. Null or none for guaranteed cost policies.. Valid values are `retrospective_rated|large_deductible|self_insured|captive|none`',
    `minimum_premium_amount` DECIMAL(18,2) COMMENT 'The minimum premium amount guaranteed to the carrier regardless of actual payroll volume, as stipulated in the policy terms. Relevant for low-volume periods and ensures the carrier recovers minimum administrative costs.',
    `modified_rate_per_100` DECIMAL(18,2) COMMENT 'The effective WC premium rate per $100 of payroll after applying the experience modification factor (EMR) to the base rate. This is the rate used in actual premium calculations for payroll runs. Computed as base_rate_per_100 multiplied by experience_mod_factor.',
    `next_audit_date` DATE COMMENT 'The scheduled date for the next premium audit by the insurance carrier. Used for audit preparation planning, payroll record retention compliance, and proactive reconciliation of estimated versus actual premiums.',
    `payroll_subject_to_wc` DECIMAL(18,2) COMMENT 'The gross payroll dollar amount for the premium period that is subject to workers compensation premium calculation for this class code and state jurisdiction. Excludes non-covered remuneration per NCCI rules (e.g., tips, certain overtime premiums). Used as the basis for premium computation.',
    `policy_notes` STRING COMMENT 'Free-text field for operational notes, underwriting conditions, endorsements, or special program terms associated with this WC policy record. Used by payroll and risk management teams to document carrier-specific requirements or exceptions.',
    `policy_number` STRING COMMENT 'The externally-assigned policy number issued by the insurance carrier that uniquely identifies this workers compensation insurance policy. Used for carrier reporting, premium audit reconciliation, and regulatory filings.',
    `policy_status` STRING COMMENT 'Current lifecycle state of the workers compensation policy. Active policies are in force and covering workers; expired policies have passed their expiration date; cancelled policies were terminated before expiration; pending policies are bound but not yet effective.. Valid values are `active|expired|cancelled|pending|non_renewed`',
    `policy_type` STRING COMMENT 'Classification of the WC insurance policy structure. Guaranteed cost policies have fixed premiums; loss-sensitive policies (e.g., retrospective rated, large deductible) have premiums that vary based on actual loss experience. Drives premium calculation methodology and financial risk exposure.. Valid values are `guaranteed_cost|loss_sensitive|large_deductible|retrospective_rated|captive`',
    `policy_year` STRING COMMENT 'The four-digit calendar or fiscal year of the workers compensation policy period. Used to group premium transactions for annual audit reconciliation, loss run reporting, and year-over-year cost trend analysis.',
    `premium_basis` STRING COMMENT 'The basis on which WC premiums are calculated. In staffing, the standard basis is payroll (gross remuneration subject to WC), but some specialty programs may use flat or per-capita bases. Determines how payroll_subject_to_wc is computed.. Valid values are `payroll|remuneration|flat|per_capita`',
    `premium_period_end_date` DATE COMMENT 'The end date of the payroll period for which this WC premium transaction was calculated. Together with premium_period_start_date, defines the coverage window for the premium accrual.',
    `premium_period_start_date` DATE COMMENT 'The start date of the payroll period for which this WC premium transaction was calculated. Defines the coverage window for the premium accrual and aligns with the pay run cycle.',
    `schedule_credit_debit_pct` DECIMAL(18,2) COMMENT 'The schedule rating credit (negative value) or debit (positive value) percentage applied to the manual premium, reflecting underwriter judgment on risk characteristics not captured by the experience modification factor. Expressed as a decimal (e.g., -0.10 for a 10% credit).',
    `state_jurisdiction` STRING COMMENT 'The two-letter US state code representing the state jurisdiction under which this workers compensation policy is filed and governed. Critical for multi-state WC compliance, SUTA alignment, and state-specific rate application for temporary and contract workers.. Valid values are `^[A-Z]{2}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this workers compensation policy record was most recently modified. Used for change data capture (CDC), incremental ETL processing, and audit trail maintenance in the Databricks Silver Layer.',
    `workers_comp_code_source` STRING COMMENT 'Identifies the rating bureau or authority that issued the WC class code and rates for this policy record. Most states use NCCI; California uses WCIRB; a few states have independent bureaus. Critical for multi-state compliance and rate validation. [ENUM-REF-CANDIDATE: NCCI|WCIRB|NYBCOMP|DELAWARE|INDIANA|MICHIGAN|MINNESOTA|OTHER — promote to reference product]',
    `ytd_premium_total` DECIMAL(18,2) COMMENT 'The cumulative workers compensation premium accrued from the start of the policy year through the current premium period for this class code and state jurisdiction. Used for premium audit reconciliation, carrier reporting, and financial forecasting of WC costs.',
    CONSTRAINT pk_wc_policy PRIMARY KEY(`wc_policy_id`)
) COMMENT 'Master and transactional record for workers compensation insurance policies and premium calculations administered through TempWorks Payroll — unified SSOT for both WC policy administration and premium accrual. Policy attributes: policy number, insurance carrier, policy effective and expiration dates, state jurisdiction, experience modification factor (EMR), policy type (guaranteed cost, loss-sensitive), premium basis (payroll-based), audit frequency, and policy status. Premium transaction attributes: WC class code, NCCI class description, state jurisdiction, payroll amount subject to WC, WC rate applied per $100 of payroll, computed premium amount, experience modification factor applied, YTD premium total, premium period, and pay run reference. Supports multi-state WC compliance for temporary and contract workers, carrier reporting, premium audit reconciliation, accurate burden rate application, and cost allocation to client assignments.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`tax_filing` (
    `tax_filing_id` BIGINT COMMENT 'Primary key for tax_filing',
    `audit_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_audit. Business justification: Tax filings are subject to compliance audits by IRS, state tax authorities, and DOL. Audit scope includes payroll tax returns, deposit schedules, and withholding accuracy - audit trail links filings t',
    `client_account_id` BIGINT COMMENT 'Foreign key linking to client.client_account. Business justification: In EOR staffing arrangements (eor_arrangement_flag on tax_filing), tax filings are made on behalf of client accounts. Regulatory compliance and EOR cost allocation reporting require tracing tax filing',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: EOR (Employer of Record) arrangements are specified in MSA terms and directly govern tax filing legal entity, EIN, and employer obligations. tax_filing has eor_arrangement_flag and legal_entity_name b',
    `original_filing_tax_filing_id` BIGINT COMMENT 'Reference to the original payroll_tax_filing_id that this amended filing corrects. Null for original (non-amended) filings. Enables amendment chain tracking for IRS audit readiness.',
    `pay_run_id` BIGINT COMMENT 'Reference to the payroll run or payroll batch that generated the tax liabilities captured in this filing. Links the tax filing back to the source payroll processing event in TempWorks Payroll. Serves as the PARTY_REFERENCE (to a MASTER_AGREEMENT/processing entity) for this TRANSACTION_HEADER.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Tax filings must comply with state-specific rules governing filing deadlines, deposit schedules, and rate requirements. Staffing firms link tax filings to the governing state compliance rule for state',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: In EOR (Employer of Record) arrangements, the supplier is the legal employer who files payroll taxes under their EIN. tax_filing must reference the EOR supplier for regulatory attribution, multi-EIN t',
    `amended_filing_flag` BOOLEAN COMMENT 'Indicates whether this record represents an amended or corrected tax filing (True) versus an original filing (False). Amended filings (e.g., Form 941-X) correct errors in previously submitted returns and are tracked separately for audit purposes.',
    `balance_due_amount` DECIMAL(18,2) COMMENT 'Remaining tax balance owed to the tax authority after applying all deposits and credits (tax_liability_amount minus deposit_amount minus prior_deposit_amount). A positive value indicates underpayment; zero or negative indicates overpayment or credit.',
    `confirmation_number` STRING COMMENT 'Confirmation or acknowledgment number returned by the tax authority (e.g., EFTPS trace number, state portal confirmation) upon successful receipt of the tax deposit or filed return. Used for audit trail and dispute resolution.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this tax filing record was first created in TempWorks Payroll and ingested into the Silver Layer. Serves as the RECORD_AUDIT_CREATED field for this TRANSACTION_HEADER.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this filing record (e.g., USD). Supports international operations and EOR arrangements. Part of the MONETARY_TRIPLET for this TRANSACTION_HEADER.. Valid values are `^[A-Z]{3}$`',
    `deposit_amount` DECIMAL(18,2) COMMENT 'Actual dollar amount deposited to the tax authority for this filing period. May differ from tax_liability_amount due to prior deposits, adjustments, or credits. Net amount remitted. Part of the MONETARY_TRIPLET for this TRANSACTION_HEADER.',
    `deposit_date` DATE COMMENT 'Actual date on which the tax deposit was transmitted to the tax authority via EFTPS or state equivalent. Used to determine timeliness and calculate any late deposit penalties. Serves as the BUSINESS_EVENT_TIMESTAMP (date precision) for this TRANSACTION_HEADER.',
    `deposit_method` STRING COMMENT 'Method used to transmit the tax deposit to the tax authority. EFTPS = IRS Electronic Federal Tax Payment System (mandatory for most employers); ACH = Automated Clearing House bank transfer for state deposits; check = paper check (rare); state_portal = state-specific online payment portal.. Valid values are `EFTPS|ACH|check|state_portal`',
    `due_date` DATE COMMENT 'Statutory deadline by which this tax deposit or return must be submitted to the tax authority to avoid penalties. Determined by IRS deposit schedule rules (semi-weekly or monthly) or statutory filing deadlines for annual/quarterly returns.',
    `ein` STRING COMMENT 'IRS-assigned Employer Identification Number (EIN) of the legal entity filing this return. Required on all federal and state payroll tax filings. In EOR (Employer of Record) and co-employment models, this may reflect the EOR entitys EIN rather than the clients EIN.. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `eor_arrangement_flag` BOOLEAN COMMENT 'Indicates whether this tax filing is processed under an Employer of Record (EOR) or co-employment arrangement (True), where the staffing firm acts as the legal employer for tax purposes on behalf of a client. Affects EIN used and liability allocation.',
    `federal_income_tax_withheld` DECIMAL(18,2) COMMENT 'Total federal income tax withheld from worker wages and remitted to the IRS for this filing period. Reported on IRS Form 941 Line 3. Applies to W-2 employees; not applicable for 1099 independent contractors.',
    `fica_employee_tax_amount` DECIMAL(18,2) COMMENT 'Employee share of FICA taxes (Social Security 6.2% + Medicare 1.45%) withheld from worker paychecks and remitted as part of this filing. Applicable for W-2 employees; not applicable for 1099 independent contractors.',
    `fica_employer_tax_amount` DECIMAL(18,2) COMMENT 'Employer matching share of FICA taxes (Social Security 6.2% + Medicare 1.45%) owed by the staffing firm or EOR entity as the employer of record. Equal to the employee FICA amount under standard rules.',
    `filed_timestamp` TIMESTAMP COMMENT 'Exact date and time when the tax return was electronically submitted to the tax authority. Provides precise audit trail for compliance and IRS/DOL audit readiness. Null if return has not yet been filed.',
    `filing_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this tax filing or deposit transaction, used for reconciliation with the tax authority and TempWorks Payroll records. Serves as the BUSINESS_IDENTIFIER for this TRANSACTION_HEADER.',
    `filing_period_type` STRING COMMENT 'Frequency classification of the tax filing period. Determines deposit schedule (e.g., semi-weekly vs. monthly depositor rules under IRS Publication 15) and aligns with the form type (e.g., quarterly for 941, annual for 940).. Valid values are `weekly|bi-weekly|semi-monthly|monthly|quarterly|annual`',
    `filing_status` STRING COMMENT 'Current workflow state of the payroll tax filing or deposit obligation. pending = liability identified but not yet deposited; deposited = funds transferred to tax authority; filed = return submitted; amended = corrected filing submitted; voided = filing cancelled; rejected = filing rejected by authority. Serves as the LIFECYCLE_STATUS for this TRANSACTION_HEADER.. Valid values are `pending|deposited|filed|amended|voided|rejected`',
    `filing_type` STRING COMMENT 'The IRS or state tax form type associated with this filing obligation. Common values include: 941 (Employers Quarterly Federal Tax Return), 940 (Federal Unemployment Tax Act annual return), 944 (annual federal tax return for small employers), W-2 (Wage and Tax Statement), 1099-NEC (Non-Employee Compensation), state SUTA return, state income tax withholding return. [ENUM-REF-CANDIDATE: 941|940|944|W-2|1099-NEC|SUTA|state_income_tax|local_income_tax — promote to reference product]',
    `futa_tax_amount` DECIMAL(18,2) COMMENT 'Federal Unemployment Tax Act (FUTA) tax liability for this filing period. Calculated at 6.0% on the first $7,000 of each employees wages, net of SUTA credit (typically reducing effective rate to 0.6%). Reported on IRS Form 940.',
    `interest_amount` DECIMAL(18,2) COMMENT 'Dollar amount of interest charged by the tax authority on late or underpaid tax deposits. Accrues from the deposit due date to the actual payment date. Zero if no interest assessed.',
    `legal_entity_name` STRING COMMENT 'Full legal name of the employer entity as registered with the IRS and state tax authorities for this filing. Supports multi-entity payroll structures including EOR, PEO, and co-employment arrangements.',
    `notes` STRING COMMENT 'Free-text notes or comments entered by payroll staff regarding this tax filing, such as reasons for amendments, penalty dispute details, or special handling instructions. Supports operational context for compliance reviews.',
    `overpayment_amount` DECIMAL(18,2) COMMENT 'Amount overpaid to the tax authority for this filing period. May be applied as a credit to the next period or requested as a refund. Null or zero if no overpayment exists.',
    `payroll_period_end_date` DATE COMMENT 'Last date of the payroll period covered by this tax filing. Defines the end of the wage and tax liability window for this return.',
    `payroll_period_start_date` DATE COMMENT 'First date of the payroll period covered by this tax filing. Combined with payroll_period_end_date, defines the wage and tax liability window for this return.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Dollar amount of IRS or state-assessed penalties for late deposit, late filing, or underpayment of payroll taxes. Zero if no penalties assessed. Critical for compliance monitoring and SLA tracking.',
    `prior_deposit_amount` DECIMAL(18,2) COMMENT 'Total tax deposits made in prior periods within the same filing period that are applied against the current tax liability. Used for reconciliation between cumulative deposits and the final return balance due.',
    `state_code` STRING COMMENT 'Two-letter U.S. state or territory code (ISO 3166-2:US) for the jurisdiction of this filing. Null for federal-level filings. Critical for multi-state payroll tax compliance across all worker assignment states.. Valid values are `^[A-Z]{2}$`',
    `state_income_tax_withheld` DECIMAL(18,2) COMMENT 'Total state income tax withheld from worker wages and remitted to the state tax authority for this filing period. Applicable for states with income tax; null for states without state income tax (e.g., TX, FL, WA).',
    `suta_tax_amount` DECIMAL(18,2) COMMENT 'State Unemployment Tax Act (SUTA) tax liability for this filing period. Rate and wage base vary by state and employer experience rating. Critical for multi-state staffing operations where workers are assigned across multiple states.',
    `tax_authority_level` STRING COMMENT 'Jurisdictional level of the tax authority receiving this filing: federal (IRS/DOL), state (state revenue or unemployment agency), or local (city/county tax authority). Supports multi-state payroll compliance reporting and audit readiness.. Valid values are `federal|state|local`',
    `tax_authority_name` STRING COMMENT 'Name of the federal, state, or local tax authority to which this filing or deposit is submitted (e.g., IRS, California EDD, New York State DTF, City of Philadelphia Revenue Department). Used for multi-jurisdiction payroll compliance tracking.',
    `tax_liability_amount` DECIMAL(18,2) COMMENT 'Total tax liability computed for this filing period based on taxable wages and applicable tax rates. Represents the gross amount owed to the tax authority before any prior deposits or credits are applied. Part of the MONETARY_TRIPLET for this TRANSACTION_HEADER.',
    `tax_quarter` STRING COMMENT 'Calendar quarter (1–4) to which this filing applies. Applicable for quarterly filings such as IRS Form 941 and quarterly SUTA returns. Null for non-quarterly filing types.',
    `tax_year` STRING COMMENT 'Four-digit calendar year to which this tax filing applies (e.g., 2024). Used for annual reconciliation, W-2/1099 processing, and IRS/DOL audit readiness.',
    `total_taxable_wages` DECIMAL(18,2) COMMENT 'Aggregate gross taxable wages subject to the specific tax type covered by this filing for the filing period. Basis for computing the total tax liability. Excludes non-taxable fringe benefits and pre-tax deductions where applicable.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this tax filing record, including status changes, amendments, or deposit updates. Serves as the RECORD_AUDIT_UPDATED field for this TRANSACTION_HEADER.',
    `worker_classification` STRING COMMENT 'Classification of workers covered by this filing: W-2 for employees subject to withholding and employer taxes, 1099 for independent contractors (IC) subject only to self-employment tax reporting, or both for filings covering mixed worker populations. Critical for IRS worker classification compliance.. Valid values are `W-2|1099|both`',
    `worker_count` STRING COMMENT 'Number of workers (W-2 employees or 1099 contractors) included in this tax filing period. Reported on IRS Form 941 Line 1 as the number of employees who received wages. Supports headcount analytics and workforce planning.',
    CONSTRAINT pk_tax_filing PRIMARY KEY(`tax_filing_id`)
) COMMENT 'Transactional record tracking payroll tax deposit and filing obligations submitted to federal, state, and local tax authorities. Captures filing type (941, 940, SUTA, state income tax), tax authority, filing period, total taxable wages, total tax liability, deposit amount, deposit date, filing due date, filing status (pending, deposited, filed, amended), confirmation number, and penalty/interest amounts if applicable. Supports multi-state tax compliance and IRS/DOL audit readiness.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`tax_form` (
    `tax_form_id` BIGINT COMMENT 'Unique surrogate primary key for each annual tax form record (W-2, W-2c, 1099-NEC, 1099-MISC) generated in TempWorks Payroll. Globally unique across all form types and tax years.',
    `assignment_id` BIGINT COMMENT 'Foreign key linking to placement.assignment. Business justification: W-2 multi-state allocation and state tax filing require the assignment context (work state, client, job classification). tax_form has profile_id but no assignment linkage. State W-2 preparation and mu',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: W-2/1099 forms must reference MSA for co-employment determination and tax responsibility allocation. Critical for EOR/PEO arrangements where legal employer status affects tax filing obligations and de',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IRS 1099-NEC and 1099-MISC issuance for IC contractors is directly governed by the IC agreements form_1099_reporting_flag and worker_classification_basis. Tax form generation for IC workers requires ',
    `original_form_tax_form_id` BIGINT COMMENT 'Reference to the original tax_form record that this corrected form (W-2c or amended 1099) supersedes. Null for original (non-corrected) forms. Enables correction history chain tracking for audit and IRS reconciliation.',
    `profile_id` BIGINT COMMENT 'Reference to the worker or independent contractor (IC) for whom this tax form was generated. Links to the candidate/worker master record in Bullhorn ATS or TempWorks Payroll.',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: 1099-NEC forms are issued to IC/SOW workers. IRS 1099 preparation requires tracing total payments to the specific SOW engagement (IC classification, total invoiced amount). A staffing tax compliance e',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: For 1099-NEC IC worker payments and W-2 EOR arrangements, the supplier is the payer/employer of record issuing the tax form. tax_form.supplier_id enables payer-of-record attribution for IRS filing, su',
    `tax_filing_id` BIGINT COMMENT 'Foreign key linking to payroll.tax_filing. Business justification: A tax_form (W-2 or 1099-NEC/MISC) is submitted to tax authorities as part of a tax filing event (annual W-2 transmittal via Form W-3, 1099 filing via Form 1096, or electronic FIRE/BSO submission). Add',
    `work_authorization_id` BIGINT COMMENT 'Foreign key linking to credentialing.work_authorization. Business justification: W-2 and 1099 tax forms for visa-sponsored workers require work authorization details — nonresident alien treatment, treaty exemptions, and LCA compliance all depend on visa category. Tax Form Complia',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: W-2 vs. 1099-NEC tax form type is directly determined by worker classification. Staffing firms must link tax forms to the governing classification determination for IRS misclassification audit defense',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this tax form record was first created in TempWorks Payroll during the year-end tax form generation process. Supports audit trail and SOC 2 compliance.',
    `distribution_date` DATE COMMENT 'Date the workers copy of the tax form was distributed (mailed, electronically delivered, or handed in person). Must be on or before January 31 of the year following the tax year per IRS requirements.',
    `distribution_method` STRING COMMENT 'Method used to distribute the workers copy of the tax form. Mail: physical paper mailed to worker address. Electronic: delivered via secure online portal (requires worker consent). In-person: handed directly to worker.. Valid values are `mail|electronic|in_person`',
    `efile_accepted_timestamp` TIMESTAMP COMMENT 'Date and time when the IRS FIRE system or SSA ACCUWAGE system accepted the e-file submission for this tax form. Null if not yet filed or if paper-filed. Critical for IRS filing deadline compliance.',
    `efile_submission_reference` STRING COMMENT 'IRS or SSA-assigned submission identifier returned upon successful e-file transmission. For W-2s: SSA ACCUWAGE submission ID. For 1099s: IRS FIRE system submission ID. Used to track filing status and retrieve acknowledgements.',
    `employer_ein` STRING COMMENT 'Federal Employer Identification Number (EIN) of the staffing company or EOR entity issuing the tax form. Appears in Box c of W-2 and Payer TIN field of 1099 forms. Required for IRS e-filing and state tax agency submissions.. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `filing_status` STRING COMMENT 'Current lifecycle state of the tax form. Draft: form generated but not yet submitted to IRS/SSA. Filed: successfully submitted. Corrected: a W-2c or amended 1099 has been issued. Voided: form cancelled. Accepted: IRS/SSA e-file acknowledgement received.. Valid values are `draft|filed|corrected|voided|accepted`',
    `form_type` STRING COMMENT 'Discriminator identifying the IRS tax form type. W-2 for W-2 employees and temporary workers; W-2c for corrected W-2s; 1099-NEC for independent contractor (IC) nonemployee compensation; 1099-MISC for miscellaneous income. Drives form-specific field population and filing rules.. Valid values are `W-2|W-2c|1099-NEC|1099-MISC`',
    `is_corrected` BOOLEAN COMMENT 'True if this record represents a corrected tax form (W-2c or amended 1099). The corrected checkbox is checked on the physical form. Links to the original form via original_form_id for correction history tracking.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this tax form record was most recently modified (e.g., correction applied, filing status updated, distribution recorded). Supports audit trail and change tracking.',
    `local_income_tax_withheld_box19` DECIMAL(18,2) COMMENT 'W-2 Box 19: Total local income tax withheld from the workers wages. Reported to the applicable local tax authority. Null if no local tax applies.',
    `local_wages_box18` DECIMAL(18,2) COMMENT 'W-2 Box 18: Total wages subject to local income tax withholding (e.g., city or county taxes). Applicable in jurisdictions such as New York City, Philadelphia, or Ohio municipalities. Null if no local tax applies.',
    `misc_other_income_box3` DECIMAL(18,2) COMMENT '1099-MISC Box 3: Other income payments not reportable in other boxes, such as prizes, awards, or taxable per diem amounts exceeding IRS limits. Null for W-2 and 1099-NEC form types.',
    `misc_rents_box1` DECIMAL(18,2) COMMENT '1099-MISC Box 1: Rent payments of $600 or more paid to a landlord or property owner. Applicable when staffing company pays office or facility rent to a non-corporate payee. Null for W-2 and 1099-NEC form types.',
    `nec_compensation_box1` DECIMAL(18,2) COMMENT '1099-NEC Box 1: Total nonemployee compensation paid to an independent contractor (IC) during the tax year. Includes fees, commissions, prizes, and awards for services rendered. Null for W-2 form types. Threshold: $600 or more triggers filing requirement.',
    `nec_federal_tax_withheld_box4` DECIMAL(18,2) COMMENT '1099-NEC Box 4: Federal income tax withheld under backup withholding rules (24% rate) when the contractor failed to provide a valid TIN or IRS notified backup withholding is required. Null for W-2 form types.',
    `paper_filed` BOOLEAN COMMENT 'True if this tax form was submitted to the IRS/SSA via paper rather than electronic filing. Staffing companies filing 10 or more forms are required to e-file per IRS regulations. Tracks compliance with mandatory e-file thresholds.',
    `payer_tin` STRING COMMENT 'Payers Taxpayer Identification Number (TIN) as reported on 1099 forms. Typically the same as the employer EIN but may differ for EOR or co-employment arrangements where a third-party PEO is the payer of record.. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `recipient_tin_type` STRING COMMENT 'Type of TIN used for the recipient/worker on this tax form. SSN for W-2 employees and individual contractors; EIN for contractors operating as a business entity; ITIN for foreign workers without an SSN. Drives IRS validation rules.. Valid values are `SSN|EIN|ITIN`',
    `state_code` STRING COMMENT 'Two-letter US state abbreviation for the primary state of employment reported on this tax form (W-2 Box 15 state code). Drives state tax agency filing and multi-state payroll compliance. For workers with wages in multiple states, the primary state is recorded here.. Valid values are `^[A-Z]{2}$`',
    `state_employer_number` STRING COMMENT 'State-assigned employer identification number used for state income tax withholding reporting (W-2 Box 15). Required for state e-filing submissions. Format varies by state.',
    `state_filing_status` STRING COMMENT 'Current status of the state tax agency filing for this form. Not_required: state has no income tax or filing not required. Pending: prepared but not yet submitted. Filed: submitted to state agency. Accepted: state agency confirmed receipt. Supports multi-state payroll compliance tracking.. Valid values are `not_required|pending|filed|accepted`',
    `state_income_tax_withheld_box17` DECIMAL(18,2) COMMENT 'W-2 Box 17: Total state income tax withheld from the workers wages. Reported to the applicable state tax agency. Null for 1099 form types or states with no income tax.',
    `state_wages_box16` DECIMAL(18,2) COMMENT 'W-2 Box 16: Total wages subject to state income tax withholding. May differ from Box 1 federal wages due to state-specific pre-tax exclusions. Supports multi-state payroll compliance. Null for 1099 form types.',
    `tax_year` STRING COMMENT 'The calendar tax year (e.g., 2024) for which this form reports wages, compensation, and withholdings. Drives IRS filing deadlines and year-end reconciliation cycles.',
    `w2_box12_code_a_amount` DECIMAL(18,2) COMMENT 'W-2 Box 12 Code A: Uncollected Social Security tax on tips. One of up to four Box 12 entries capturing pre-tax benefit and special compensation amounts. Null if not applicable.',
    `w2_box12_codes` STRING COMMENT 'Pipe-delimited list of IRS Box 12 codes reported on this W-2 (e.g., D|DD|W). Code D = 401(k) elective deferrals; Code DD = employer-sponsored health coverage cost; Code W = HSA employer contributions; Code C = taxable cost of group-term life insurance. Supports multi-code scenarios common in staffing. Null for 1099 form types. [ENUM-REF-CANDIDATE: A|B|C|D|DD|E|F|G|H|J|K|L|M|N|P|Q|R|S|T|V|W|Y|Z|AA|BB|DD|EE|FF|GG|HH — promote to reference product]',
    `w2_box12_total_amount` DECIMAL(18,2) COMMENT 'Aggregate dollar amount across all Box 12 codes reported on this W-2. Used for year-end reconciliation of pre-tax benefit deductions (401k, HSA, health coverage). Null for 1099 form types.',
    `w2_federal_tax_withheld_box2` DECIMAL(18,2) COMMENT 'W-2 Box 2: Total federal income tax withheld from the workers wages during the tax year. Reported to IRS and used by worker for federal tax return filing. Null for 1099 form types.',
    `w2_medicare_tax_withheld_box6` DECIMAL(18,2) COMMENT 'W-2 Box 6: Employees share of Medicare (FICA) tax withheld. Equals 1.45% of Box 5 wages, plus 0.9% Additional Medicare Tax for high earners. Null for 1099 form types.',
    `w2_medicare_wages_box5` DECIMAL(18,2) COMMENT 'W-2 Box 5: Total wages and tips subject to Medicare (FICA) tax. No wage base cap applies. Includes wages above the Social Security wage base. Null for 1099 form types.',
    `w2_other_compensation_box14` DECIMAL(18,2) COMMENT 'W-2 Box 14: Employer-reported informational amounts such as state disability insurance (SDI) withheld, union dues, educational assistance, or other items not captured in other boxes. Null for 1099 form types.',
    `w2_retirement_plan_box13` BOOLEAN COMMENT 'W-2 Box 13 checkbox: True if the worker was an active participant in an employer-sponsored retirement plan (401k, SIMPLE IRA, etc.) during the tax year. Affects IRA deductibility on the workers personal return. Null for 1099 form types.',
    `w2_ss_tax_withheld_box4` DECIMAL(18,2) COMMENT 'W-2 Box 4: Employees share of Social Security (FICA) tax withheld. Equals 6.2% of Box 3 wages up to the wage base. Null for 1099 form types.',
    `w2_ss_wages_box3` DECIMAL(18,2) COMMENT 'W-2 Box 3: Total wages subject to Social Security (FICA) tax, capped at the annual Social Security wage base limit. Null for 1099 form types.',
    `w2_statutory_employee_box13` BOOLEAN COMMENT 'W-2 Box 13 checkbox: True if the worker is classified as a statutory employee (e.g., certain drivers, traveling salespeople). Affects self-employment tax treatment. Null for 1099 form types.',
    `w2_third_party_sick_pay_box13` BOOLEAN COMMENT 'W-2 Box 13 checkbox: True if the worker received third-party sick pay (e.g., from an insurance carrier) that is included in wages. Common in staffing for workers on short-term disability. Null for 1099 form types.',
    `w2_wages_box1` DECIMAL(18,2) COMMENT 'W-2 Box 1: Total taxable wages, tips, and other compensation subject to federal income tax withholding. Excludes pre-tax benefit deductions (401k, health insurance). Null for 1099 form types.',
    `worker_address_city` STRING COMMENT 'City of the workers mailing address as printed on the tax form. Used for form distribution and state tax filing jurisdiction determination.',
    `worker_address_line1` STRING COMMENT 'First line of the workers mailing address as printed on the tax form for distribution. Required for paper form mailing and IRS/SSA filing. Appears in Box f of W-2 and Recipient Address of 1099.',
    `worker_address_state` STRING COMMENT 'Two-letter US state code of the workers mailing address. Drives state tax filing jurisdiction and multi-state payroll compliance rules.',
    `worker_address_zip` STRING COMMENT 'ZIP or ZIP+4 postal code of the workers mailing address as printed on the tax form.. Valid values are `^[0-9]{5}(-[0-9]{4})?$`',
    `worker_copy_distributed` BOOLEAN COMMENT 'True if the workers copy of the tax form (Copy B for W-2, Copy B for 1099) has been distributed to the worker by the IRS deadline (January 31). Tracks compliance with worker distribution requirements.',
    `worker_legal_name` STRING COMMENT 'Full legal name of the worker or independent contractor as it appears on the tax form (W-2 Box e or 1099 Recipient Name). Must match SSA records for W-2 employees to avoid name/SSN mismatch errors.',
    `worker_ssn` STRING COMMENT 'Workers Social Security Number (SSN) as reported on the tax form. Appears in Box a of W-2 and Recipient TIN field of 1099 forms. Masked in most operational views; full value required only for IRS e-filing and SSA submission. Governed by FCRA and IRS regulations.. Valid values are `^[0-9]{3}-[0-9]{2}-[0-9]{4}$`',
    `workers_comp_state` STRING COMMENT 'Two-letter state code for the state under which workers compensation (Workers Comp) insurance was carried for this worker during the tax year. Relevant for W-2 employees on temporary assignments. Used in year-end workers comp audit reconciliation.. Valid values are `^[A-Z]{2}$`',
    CONSTRAINT pk_tax_form PRIMARY KEY(`tax_form_id`)
) COMMENT 'Master record representing annual tax forms generated for both W-2 employees/temporary workers and 1099 independent contractors. For W-2 forms: captures Box 1 wages, Box 2 federal income tax withheld, Boxes 3-6 Social Security and Medicare wages and withholdings, state and local wages and withholdings, pre-tax benefit amounts (Box 12 codes), and W-2 filing status. For 1099 forms: captures 1099-NEC nonemployee compensation (Box 1), 1099-MISC miscellaneous income, backup withholding, and state income. Stores tax year, worker/contractor identifier, employer/payer EIN, form type discriminator (W-2, W-2c, 1099-NEC, 1099-MISC), filing status (draft, filed, corrected), e-file confirmation, and correction history. SSOT for ALL annual tax form reporting — unified W-2 and 1099 populations common in staffing operations where both employee and IC worker types coexist. Supports IRS e-filing, state filing, worker distribution, and year-end reconciliation.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`tax_withholding_election` (
    `tax_withholding_election_id` BIGINT COMMENT 'Unique surrogate identifier for each tax withholding election record. Primary key for the tax_withholding_election data product in the payroll domain.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment associated with this withholding election, enabling assignment-level tax configuration for multi-assignment workers.',
    `direct_hire_id` BIGINT COMMENT 'Foreign key linking to placement.direct_hire. Business justification: Direct hire employees submit W-4 elections when staffing firm processes payroll under PEO or transition arrangements. Links tax elections to permanent placement for withholding compliance.',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC agreements worker_classification_basis directly governs withholding election setup — true IC workers are typically exempt from withholding. Staffing payroll teams must reference the IC agreement w',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: Tax withholding elections are collected during onboarding. Linking to onboarding engagement supports IRS compliance verification that W-4/state tax forms were obtained before first paycheck, required ',
    `profile_id` BIGINT COMMENT 'Reference to the worker (W-2 employee or 1099 independent contractor) whose tax withholding elections are captured in this record. Links to the candidate or worker master record.',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: SOW/IC workers have distinct withholding elections (backup withholding for 1099, W-2 for EOR SOW). Tax withholding elections must reference the SOW engagement to determine correct tax treatment. IRS b',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Withholding elections must comply with state-specific rules (mandatory withholding states, flat rate states, exemption eligibility). Staffing firms link withholding elections to the governing state co',
    `superseded_by_election_tax_withholding_election_id` BIGINT COMMENT 'Reference to the newer tax_withholding_election record that replaced this one. Populated when election_status = superseded. Enables forward-chaining of the election history for audit trails.',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Tax withholding elections (W-4) are only applicable to W-2 employees, not independent contractors. Worker classification determines withholding eligibility and form type - misclassified workers trigge',
    `allowances_claimed` STRING COMMENT 'Number of withholding allowances claimed by the worker on pre-2020 W-4 forms. Each allowance reduces the amount of federal income tax withheld. Applicable only for W-4 forms prior to the 2020 redesign. Null for 2020+ W-4 forms which use the step-based approach.',
    `approved_by` STRING COMMENT 'Username or employee ID of the payroll supervisor or manager who reviewed and approved this withholding election entry. Required for IRS lock-in letter overrides and exempt status elections as part of internal controls.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this withholding election record was first created in the payroll system. Supports audit trail, SOC 2 Type II compliance, and IRS record retention requirements for withholding forms.',
    `deductions_amount` DECIMAL(18,2) COMMENT 'Dollar amount of itemized or other deductions entered in Step 4b of the 2020+ W-4. Reduces withholding by accounting for deductions that exceed the standard deduction. Null for pre-2020 W-4 forms.',
    `dependent_credit_amount` DECIMAL(18,2) COMMENT 'Dollar amount of qualifying dependent credits entered in Step 3 of the 2020+ redesigned W-4. Reduces the amount of income subject to withholding. Includes child tax credit ($2,000 per qualifying child under 17) and other dependent credits ($500 per other dependent). Null for pre-2020 W-4 forms.',
    `document_reference_code` STRING COMMENT 'Reference identifier for the physical or electronic withholding form document stored in the document management system (e.g., DocuSign CLM or SAP SuccessFactors document repository). Enables retrieval of the original signed form for audit and compliance verification.',
    `effective_date` DATE COMMENT 'Date on which this withholding election becomes effective and begins driving tax withholding calculations in pay runs. Aligns with IRS requirement that new W-4 elections take effect no later than the start of the first payroll period ending on or after the 30th day after the form is received.',
    `election_notes` STRING COMMENT 'Free-text notes entered by payroll staff regarding this withholding election. May include reasons for IRS lock-in overrides, documentation of verbal instructions, or notes on unusual withholding configurations.',
    `election_number` STRING COMMENT 'Externally-visible business identifier for this withholding election record, used for audit trails, payroll processing references, and worker communications (e.g., TWE-2024-00123).',
    `election_source` STRING COMMENT 'The channel or method through which the withholding election was submitted. Paper form = physical W-4 or state form submitted; Electronic self-service = worker submitted via online portal (e.g., SAP SuccessFactors ESS); Employer default = system default applied when no form received; IRS lock-in = IRS-mandated withholding rate overriding worker election; Verbal instruction = documented verbal request.. Valid values are `paper_form|electronic_self_service|employer_default|irs_lock_in|verbal_instruction`',
    `election_status` STRING COMMENT 'Current lifecycle state of this withholding election. Active = currently driving withholding calculations; Superseded = replaced by a newer election; Pending = submitted but not yet effective; Cancelled = voided before taking effect; Expired = past the expiration date.. Valid values are `active|superseded|pending|cancelled|expired`',
    `election_version` STRING COMMENT 'Sequential version number for withholding elections for the same worker and jurisdiction. Increments each time the worker submits a new withholding form. Enables tracking of election history and supersession chain for audit and compliance purposes.',
    `entered_by` STRING COMMENT 'Username or employee ID of the payroll staff member or system process that entered this withholding election into TempWorks Payroll. Supports audit trail requirements for payroll compliance and SOC 2 Type II controls.',
    `expiration_date` DATE COMMENT 'Date on which this withholding election expires and is no longer valid. Applicable for exempt-from-withholding elections which expire annually (February 15 of the following year per IRS rules), or for state-specific elections with defined validity periods.',
    `filing_status` STRING COMMENT 'The workers federal or state tax filing status as declared on the withholding form. Drives the applicable standard deduction and tax bracket used in withholding calculations. Values align with IRS filing status categories.. Valid values are `single|married_filing_jointly|married_filing_separately|head_of_household|qualifying_surviving_spouse`',
    `flat_withholding_rate_pct` DECIMAL(18,2) COMMENT 'Fixed percentage rate applied to gross wages for income tax withholding when the withholding method is percentage or flat_amount. Expressed as a decimal (e.g., 0.2200 = 22%). Used for supplemental wage withholding at the IRS flat supplemental rate or for state flat-rate withholding.',
    `form_type` STRING COMMENT 'The specific tax withholding form type submitted by the worker. Examples include W-4 (federal), W-4P (pension), state equivalents (e.g., CA DE-4, NY IT-2104, IL W-4, TX no state income tax). [ENUM-REF-CANDIDATE: W-4|W-4P|W-4S|W-4V|DE-4|IT-2104|IL-W-4|VA-4|NC-4|GA-G-4 — promote to reference product]',
    `irs_lock_in_allowances` STRING COMMENT 'The maximum number of withholding allowances permitted by the IRS lock-in letter, overriding the workers own W-4 election. Employer must not allow the worker to claim more allowances than this value.',
    `irs_lock_in_filing_status` STRING COMMENT 'The filing status mandated by the IRS lock-in letter, overriding the workers own W-4 election. Populated only when an IRS lock-in letter is in effect. Employer must use this status for withholding calculations.. Valid values are `single|married_filing_jointly|head_of_household`',
    `irs_lock_in_letter_date` DATE COMMENT 'Date of the IRS lock-in letter received by the employer mandating a specific withholding rate for this worker. When present, the employer must withhold at the IRS-specified rate regardless of the workers W-4 elections. Null if no lock-in letter applies.',
    `is_exempt_from_withholding` BOOLEAN COMMENT 'Indicates whether the worker has claimed exemption from federal or state income tax withholding. True = worker claims exempt status and no income tax will be withheld. Exempt status expires February 15 each year and must be renewed. Employer must retain the exempt W-4 and notify IRS if required.',
    `is_state_exempt_from_withholding` BOOLEAN COMMENT 'Indicates whether the worker has claimed exemption from state income tax withholding on the state withholding form. Exempt criteria and renewal requirements vary by state.',
    `jurisdiction_type` STRING COMMENT 'Indicates whether this election applies to federal, state, or local tax withholding. Federal elections are governed by IRS W-4; state elections by equivalent state withholding forms; local elections by municipality-specific forms.. Valid values are `federal|state|local`',
    `locality_name` STRING COMMENT 'Name of the local taxing jurisdiction (city, county, or municipality) for local income tax withholding elections. Applicable in states with local income taxes such as Ohio, Pennsylvania, Kentucky, and New York City.',
    `multiple_jobs_flag` BOOLEAN COMMENT 'Indicates whether the worker checked the Step 2 multiple jobs checkbox on the 2020+ W-4, signaling they hold multiple concurrent jobs or their spouse also works. When true, withholding is calculated using the higher withholding rate tables to prevent under-withholding.',
    `nonresident_alien_flag` BOOLEAN COMMENT 'Indicates whether the worker is a nonresident alien (NRA) for U.S. tax purposes. NRA workers are subject to special withholding rules under IRS Publication 15 and must follow specific W-4 instructions (cannot claim exempt, must add an additional amount to wages for withholding calculation). Relevant for staffing firms placing international workers.',
    `pay_frequency` STRING COMMENT 'The pay frequency associated with this withholding election, used to annualize wages for withholding table lookups. Must match the workers actual pay frequency in the pay run. Drives the correct withholding amount per period.. Valid values are `weekly|biweekly|semimonthly|monthly|daily`',
    `received_date` DATE COMMENT 'Date the withholding election form was received by the employer or payroll department. Used to determine the required effective date per IRS rules (must take effect no later than the first payroll period ending on or after the 30th day after receipt).',
    `state_additional_withholding_amount` DECIMAL(18,2) COMMENT 'Additional flat dollar amount the worker requests to be withheld for state income tax beyond the calculated state withholding. Applied per pay period in addition to the standard state withholding calculation.',
    `state_allowances_claimed` STRING COMMENT 'Number of withholding allowances claimed on the state withholding form. Many states still use an allowance-based system independent of the federal W-4 redesign (e.g., California DE-4, New York IT-2104). Null for states with no income tax or states that have adopted the federal W-4.',
    `state_code` STRING COMMENT 'Two-letter USPS state abbreviation identifying the state jurisdiction for state or local withholding elections. Null for federal elections. Supports multi-state payroll compliance across all states where Staffing Hr places workers.. Valid values are `^[A-Z]{2}$`',
    `state_filing_status` STRING COMMENT 'The workers filing status as declared on the state withholding form, which may differ from the federal filing status. State-specific values vary by jurisdiction (e.g., California uses single, married, head of household with different withholding tables). [ENUM-REF-CANDIDATE: single|married|married_higher_rate|head_of_household|exempt — promote to reference product]',
    `supplemental_wage_method` STRING COMMENT 'Method used to withhold income tax on supplemental wages (bonuses, commissions, overtime, per diem above IRS threshold). Flat rate = mandatory 22% federal flat rate for supplemental wages under $1M; Aggregate = combined with regular wages using withholding tables; Optional flat = employer elects flat rate when not mandatory.. Valid values are `flat_rate|aggregate|optional_flat`',
    `treaty_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country with which the worker claims a U.S. tax treaty benefit, potentially reducing or eliminating withholding on certain income types. Applicable for nonresident alien workers claiming treaty exemptions via Form 8233 or W-8BEN.. Valid values are `^[A-Z]{3}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this withholding election record was last modified. Tracks changes to election data for audit trail and data lineage purposes in the Databricks Silver Layer.',
    `w4_form_version_year` STRING COMMENT 'The tax year version of the W-4 or equivalent withholding form submitted by the worker. Critical because the 2020 redesigned W-4 eliminated allowances and introduced a new step-based structure. Pre-2020 forms use allowances; 2020+ forms use Step 3 dependent credits and Step 4 adjustments.',
    `withholding_method` STRING COMMENT 'The calculation method used to compute income tax withholding for this worker. Percentage method uses IRS Publication 15-T tables; Wage bracket method uses bracket tables; Flat amount applies a fixed dollar amount; Annualized projects annual income for withholding; Cumulative adjusts for year-to-date withholding.. Valid values are `percentage|flat_amount|wage_bracket|annualized|cumulative`',
    `worker_type` STRING COMMENT 'Classification of the worker for tax withholding purposes. W-2 = employee subject to income tax withholding and FICA; 1099 = independent contractor (IC) not subject to employer withholding; EOR = Employer of Record arrangement where the EOR entity handles withholding. Drives whether withholding elections are applicable.. Valid values are `w2|1099|eor`',
    CONSTRAINT pk_tax_withholding_election PRIMARY KEY(`tax_withholding_election_id`)
) COMMENT 'Master record capturing a workers federal and state tax withholding elections as submitted via W-4 (federal) and equivalent state withholding forms. Stores filing status (single, married, head of household), number of allowances or Step 3 dependent credits (post-2020 W-4), additional withholding amount, exempt from withholding flag, state withholding form type, state-specific elections, effective date, and election source (paper form, electronic self-service). Drives tax withholding calculation in each pay run.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`task_checklist` (
    `task_checklist_id` BIGINT COMMENT 'Unique identifier for the task checklist template. Primary key.',
    `client_account_id` BIGINT COMMENT 'Reference to the specific client account if this is a client-specific checklist template. Nullable for general templates.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSA specifies background_check_required_flag, drug_screen_required_flag, everify_required_flag, and i9 requirements that directly drive task checklist configuration. Staffing onboarding teams build cl',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Onboarding task checklists are governed by credential packages — the package defines which BGC, drug screen, and credentialing tasks are required. Direct FK replaces denormalized boolean flags (requir',
    `job_category_id` BIGINT COMMENT 'Foreign key linking to joborder.job_category. Business justification: Onboarding checklists are configured by job category - healthcare roles require medical credentialing tasks, IT roles require system access provisioning, construction roles require safety certificatio',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Client-specific onboarding checklists vary by work site characteristics (union facilities, secure locations, remote sites). Staffing operations require location-specific task templates for compliance ',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP managed programs define program-specific onboarding compliance requirements. Task checklists (compliance_driven_flag, mandatory_flag) must be linked to the managed program to enable program-level ',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Onboarding and placement task checklists are configured based on state compliance rules (e.g., California-specific I-9 timing, state drug screen laws, paid sick leave notice requirements). Linking tas',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Vendor agreements specify background_check_required_flag, drug_screen_required_flag, and everify_required_flag for supplier-provided workers. Task checklists for supplier worker onboarding must enforc',
    `vms_program_id` BIGINT COMMENT 'Foreign key linking to client.vms_program. Business justification: VMS programs specify compliance requirements (bgc_required, drug_screen_required, everify_required on vms_program) that directly drive task checklist configuration (requires_bgc_flag, requires_drug_sc',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: Onboarding task checklists are location-specific: site safety orientation, drug screen protocols, and badge requirements vary by work location. task_checklist has location_id (→client.location) but pl',
    `active_status` STRING COMMENT 'Current lifecycle status of the checklist template: active (in use), inactive (temporarily disabled), draft (under development), or archived (retired but retained for historical reference).. Valid values are `active|inactive|draft|archived`',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether completion of this checklist requires formal approval or sign-off before the worker can start assignment (True) or is informational only (False).',
    `checklist_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the checklist template for system integration and reporting (e.g., HC-TEMP-ONB, IT-CTR-ONB).. Valid values are `^[A-Z0-9_-]{3,20}$`',
    `checklist_name` STRING COMMENT 'Business-friendly name of the task checklist template (e.g., Healthcare Temp Onboarding, IT Contractor Onboarding, Light Industrial Assignment End).',
    `checklist_type` STRING COMMENT 'Category of the checklist template indicating the business process it supports: onboarding (new worker start), offboarding (assignment end), redeployment (worker reassignment), or extension (assignment continuation).. Valid values are `onboarding|offboarding|redeployment|extension`',
    `client_specific_flag` BOOLEAN COMMENT 'Indicates whether this checklist template is customized for a specific client account (True) or is a general template applicable across multiple clients (False).',
    `compliance_driven_flag` BOOLEAN COMMENT 'Indicates whether this checklist is driven by regulatory or compliance requirements (True) such as I-9, E-Verify, background checks, or is purely operational (False).',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this checklist template version was first created in the system.',
    `division_code` STRING COMMENT 'Business division or vertical this checklist is designed for (e.g., Healthcare, IT, Light Industrial, Professional). Nullable if checklist is division-agnostic.',
    `effective_date` DATE COMMENT 'Date from which this checklist template version becomes active and available for use in creating task assignments.',
    `estimated_completion_days` STRING COMMENT 'Expected number of business days required to complete all tasks in this checklist under normal circumstances. Used for planning and Service Level Agreement (SLA) management.',
    `expiration_date` DATE COMMENT 'Date after which this checklist template version is no longer active. Nullable for templates with indefinite validity.',
    `mandatory_flag` BOOLEAN COMMENT 'Indicates whether completion of this checklist is mandatory (True) for the associated placement type and scenario, or optional (False).',
    `modified_by` STRING COMMENT 'Username or identifier of the user who last modified this checklist template version.',
    `modified_timestamp` TIMESTAMP COMMENT 'Date and time when this checklist template version was last modified.',
    `notes` STRING COMMENT 'Free-text field for additional notes, special instructions, or context about this checklist template that does not fit structured fields.',
    `owner_role` STRING COMMENT 'Business role or department responsible for maintaining and updating this checklist template (e.g., Onboarding Team, Compliance Department, Credentialing Team).',
    `placement_type` STRING COMMENT 'Type of placement this checklist applies to: temporary, temp-to-perm, contract-to-hire, direct placement, or independent contractor (IC). Determines applicable compliance and onboarding requirements.. Valid values are `temporary|temp_to_perm|contract_to_hire|direct_placement|independent_contractor`',
    `priority_level` STRING COMMENT 'Business priority level of this checklist template indicating urgency and resource allocation: critical (blocking), high (time-sensitive), medium (standard), or low (best-effort).. Valid values are `critical|high|medium|low`',
    `requires_equipment_flag` BOOLEAN COMMENT 'Indicates whether this checklist includes equipment provisioning tasks (laptop, phone, badge, tools, Personal Protective Equipment (PPE), etc.).',
    `requires_everify_flag` BOOLEAN COMMENT 'Indicates whether this checklist includes E-Verify electronic employment eligibility verification as a required task, typically for federal contractors or specific state requirements.',
    `requires_i9_flag` BOOLEAN COMMENT 'Indicates whether this checklist includes I-9 Employment Eligibility Verification as a required task, per Immigration and Nationality Act (INA) requirements.',
    `requires_lms_training_flag` BOOLEAN COMMENT 'Indicates whether this checklist includes Learning Management System (LMS) training assignments via SAP SuccessFactors or similar platform.',
    `requires_orientation_flag` BOOLEAN COMMENT 'Indicates whether this checklist includes worker orientation or onboarding training as a required task.',
    `sla_hours` STRING COMMENT 'Service Level Agreement (SLA) target in hours for completing all tasks in this checklist from initiation. Used for performance measurement and client commitments.',
    `task_checklist_description` STRING COMMENT 'Detailed description of the checklist template purpose, scope, and intended use cases. Provides context for users selecting appropriate templates.',
    `task_count` STRING COMMENT 'Total number of individual tasks defined within this checklist template. Used for progress tracking and workload estimation.',
    `version_number` STRING COMMENT 'Version number of this checklist template. Incremented when template is revised to track changes over time and support audit trails.',
    `created_by` STRING COMMENT 'Username or identifier of the user who created this checklist template version.',
    CONSTRAINT pk_task_checklist PRIMARY KEY(`task_checklist_id`)
) COMMENT 'Reusable template defining a named collection of required onboarding or offboarding tasks for a specific scenario (e.g., temp healthcare onboarding, IT contractor onboarding, light industrial assignment end). Includes applicable placement type, division, client-specific flag, version number, effective date, and active status. Task_assignment records are instantiated from these templates for each worker engagement. Driven by requirement_rule configuration.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`payroll`.`document_collection` (
    `document_collection_id` BIGINT COMMENT 'Primary key for document_collection',
    `assignment_id` BIGINT COMMENT 'Identifier of the placement or assignment associated with this document collection, if applicable.',
    `credential_document_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_document. Business justification: Onboarding document collection references credentialing documents (licenses, certifications, BGC reports) for unified document management and compliance verification. Enables single source of truth fo',
    `direct_hire_id` BIGINT COMMENT 'Foreign key linking to placement.direct_hire. Business justification: Direct hire onboarding requires document collection (offer letter, I-9, W-4, background check consent). document_collection links to assignment but not direct_hire. Direct hire compliance audits and o',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC agreements are collected as onboarding documents. Document_collection tracks IC agreement execution status, version control, signature dates, storage location. Essential for IC agreement document l',
    `nda_id` BIGINT COMMENT 'Foreign key linking to contract.nda. Business justification: NDAs are collected during onboarding (candidate NDAs) and offboarding (exit confidentiality agreements). Document_collection tracks NDA execution, expiration dates, storage. Critical for confidentiali',
    `offboarding_record_id` BIGINT COMMENT 'Foreign key linking to timesheet.offboarding_record. Business justification: Offboarding requires document collection (exit paperwork, equipment return receipts, final timesheets). This links documents to the offboarding workflow and enables tracking offboarding completion sta',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: Document collection is a primary onboarding activity. Linking documents to the onboarding engagement enables tracking document completion status as part of overall onboarding progress and supports onb',
    `placement_compliance_check_id` BIGINT COMMENT 'Foreign key linking to compliance.placement_compliance_check. Business justification: Document collections (I-9, tax forms, NDAs, credentials) are gathered as part of the placement compliance check process. Staffing firms link collected documents to the governing compliance check recor',
    `profile_id` BIGINT COMMENT 'Identifier of the worker (candidate or employee) for whom this document was collected during onboarding or offboarding.',
    `sow_engagement_id` BIGINT COMMENT 'Foreign key linking to placement.sow_engagement. Business justification: SOW engagements require IC agreement execution, NDA, and compliance documents (W-9, COI). document_collection links to assignment but not sow_engagement. IC compliance audits and SOW onboarding comple',
    `task_checklist_id` BIGINT COMMENT 'Foreign key linking to payroll.task_checklist. Business justification: A document_collection record represents a specific document collected, signed, or acknowledged during onboarding or offboarding. The task_checklist is the reusable template that defines which document',
    `tax_withholding_election_id` BIGINT COMMENT 'Foreign key linking to payroll.tax_withholding_election. Business justification: A document_collection record for a W-4 or state equivalent tax withholding form directly produces a tax_withholding_election record. Adding tax_withholding_election_id to document_collection creates t',
    `allowances_claimed` STRING COMMENT 'Number of withholding allowances or exemptions claimed on tax form (W-4 or state withholding). Applicable to tax form document types. Used by TempWorks Payroll for withholding calculation. Note: Post-2020 W-4 uses different methodology; this field supports legacy forms.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this document collection record was first created in the system.',
    `document_name` STRING COMMENT 'Human-readable name or title of the document collected (e.g., Master Service Agreement Acknowledgment, Non-Disclosure Agreement, W-4 Federal Withholding).',
    `document_status` STRING COMMENT 'Current lifecycle status of the document in the collection and signing workflow. [ENUM-REF-CANDIDATE: pending|sent|viewed|signed|completed|declined|expired|voided — 8 candidates stripped; promote to reference product]',
    `document_type` STRING COMMENT 'Type of document collected during onboarding or offboarding. [ENUM-REF-CANDIDATE: msa_acknowledgment|nda|non_compete|handbook_acknowledgment|safety_policy|drug_screen_consent|bgc_authorization|fcra_disclosure|offer_letter|assignment_confirmation|w4|state_withholding|w9|1099_setup|i9|direct_deposit_form|emergency_contact_form|equipment_acknowledgment|confidentiality_agreement|code_of_conduct|pto_policy|benefits_enrollment|cobra_notice|final_paycheck_acknowledgment|exit_interview|property_return_form — promote to reference product]. Valid values are `msa_acknowledgment|nda|non_compete|handbook_acknowledgment|safety_policy|drug_screen_consent`',
    `document_version` STRING COMMENT 'Version identifier of the document template or form used (e.g., v2.1, 2024-Q1), ensuring compliance with the correct policy or legal version.',
    `effective_date` DATE COMMENT 'Date from which the document becomes effective or binding, particularly relevant for tax forms (W-4, state withholding) and policy acknowledgments.',
    `exempt_flag` BOOLEAN COMMENT 'Indicates whether the worker claimed exempt status from federal or state withholding on the tax form (True = exempt, False = not exempt). Applicable to W-4 and state withholding document types.',
    `expiration_date` DATE COMMENT 'Date on which the document expires and may need to be renewed or re-signed (e.g., annual policy acknowledgments, time-limited consents).',
    `filing_status` STRING COMMENT 'Federal tax filing status declared on W-4 form. Applicable only to W-4 document type. Used by TempWorks Payroll for federal withholding calculation.. Valid values are `single|married_filing_jointly|married_filing_separately|head_of_household|qualifying_widow`',
    `form_submission_date` DATE COMMENT 'Date the worker submitted the completed form to the employer or staffing agency. May differ from signed_date for forms that require additional processing or manual submission.',
    `is_electronic_signature` BOOLEAN COMMENT 'Indicates whether the document was signed electronically via DocuSign or similar platform (True) or via wet signature/manual process (False).',
    `is_required` BOOLEAN COMMENT 'Indicates whether this document is mandatory for the worker to complete onboarding or offboarding (True) or optional (False).',
    `onboarding_phase` STRING COMMENT 'Phase of the onboarding or offboarding lifecycle during which this document was collected (e.g., pre-hire, post-offer, first day, orientation, assignment start, offboarding).. Valid values are `pre_hire|post_offer|first_day|orientation|assignment_start|offboarding`',
    `rejection_reason` STRING COMMENT 'Reason the document was rejected or declined, if applicable (e.g., incomplete information, incorrect form version, illegible signature).',
    `review_date` DATE COMMENT 'Date the document was reviewed and approved by HR or compliance staff.',
    `review_notes` STRING COMMENT 'Free-text notes or comments entered by the reviewer regarding the document review, any issues identified, or follow-up actions required.',
    `sent_date` DATE COMMENT 'Date the document was sent to the worker for review or signature.',
    `signed_date` DATE COMMENT 'Date the worker signed or acknowledged the document, completing the signature workflow.',
    `signer_ip_address` STRING COMMENT 'IP address from which the worker signed the document electronically, captured for audit and compliance purposes.',
    `source_system` STRING COMMENT 'System or platform from which the document was originated or collected (e.g., DocuSign CLM, SAP SuccessFactors, TempWorks Payroll, manual upload).. Valid values are `docusign_clm|sap_successfactors|tempworks_payroll|manual_upload|bullhorn_ats`',
    `storage_location` STRING COMMENT 'Reference to the physical or digital storage location where the signed document is archived (e.g., cloud storage URI, document management system path, file share location).',
    `supersedes_prior_flag` BOOLEAN COMMENT 'Indicates whether this document supersedes or replaces a previously submitted document of the same type (True) or is a new submission (False). Particularly relevant for tax forms (W-4, state withholding) when workers update their withholding elections.',
    `tax_year` STRING COMMENT 'Tax year for which the tax form document (W-4, state withholding, W-9, 1099 setup) is applicable. Null for non-tax documents.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this document collection record was last modified or updated.',
    `viewed_date` DATE COMMENT 'Date the worker first viewed or opened the document.',
    CONSTRAINT pk_document_collection PRIMARY KEY(`document_collection_id`)
) COMMENT 'Tracks each document collected, signed, or acknowledged during the onboarding or offboarding process. Covers document type (MSA acknowledgment, NDA, non-compete, handbook acknowledgment, safety policy, drug screen consent, BGC authorization, FCRA disclosure, offer letter, assignment confirmation, W-4, state withholding, W-9, 1099 setup), document source system (DocuSign CLM, SAP SuccessFactors, TempWorks, manual upload), DocuSign envelope ID, signed date, expiration date, storage location reference, document status, and tax-form-specific fields (tax year, filing status, allowances or exemptions claimed, additional withholding amount, effective date, supersedes prior flag, form submission date). Consolidates all onboarding document types including tax form submissions into a single collection entity differentiated by document_type. Feeds payroll tax configuration in TempWorks Payroll for tax form document types (W-4, state withholding, W-9, 1099).';

-- ========= FOREIGN KEYS =========
ALTER TABLE `staffing_hr_ecm_v1`.`payroll`.`pay_stub` ADD CONSTRAINT `fk_payroll_pay_stub_pay_rate_id` FOREIGN KEY (`pay_rate_id`) REFERENCES `staffing_hr_ecm_v1`.`payroll`.`pay_rate`(`pay_rate_id`);
ALTER TABLE `staffing_hr_ecm_v1`.`payroll`.`pay_stub` ADD CONSTRAINT `fk_payroll_pay_stub_pay_run_id` FOREIGN KEY (`pay_run_id`) REFERENCES `staffing_hr_ecm_v1`.`payroll`.`pay_run`(`pay_run_id`);
